function money(v) { return new Intl.NumberFormat('es-CO', { style: 'currency', currency: 'COP', maximumFractionDigits: 0 }).format(Number(v || 0)); }
function today() { return new Date().toISOString().slice(0, 10); }
function nowLocalInput() { const d = new Date(); d.setMinutes(d.getMinutes() - d.getTimezoneOffset()); return d.toISOString().slice(0,16); }
function asset(url) { if (!url) return ''; return url.startsWith('http') ? url : `${SERVER_URL}${url}`; }
function fieldLabel(k) { return FIELD_LABELS[k] || k.replaceAll('_', ' '); }
function placeholder(k) { return PLACEHOLDERS[k] || 'Escribe aquí'; }
function canAdmin(role) { return ['owner', 'admin'].includes(role); }
function canRestaurant(role) { return ['owner', 'restaurant_owner', 'restaurant_staff'].includes(role); }
function canFullRestaurant(role) { return ['owner', 'restaurant_owner'].includes(role); }
function categoryLabel(k) { return CATEGORY_LABELS[k] || k; }
function orderStatus(k) { return ORDER_STATUS[k] || k; }
function asArray(value) { return Array.isArray(value) ? value : []; }
function safeImg(e) { e.currentTarget.onerror = null; e.currentTarget.style.display = 'none'; }
function isMembershipActive(account = {}) {
  if (!account || !['gold','platinum'].includes(String(account.membership_type || '').toLowerCase())) return false;
  if (!['active','cancelled'].includes(String(account.membership_status || '').toLowerCase())) return false;
  if (!account.membership_ends_at) return true;
  return new Date(String(account.membership_ends_at).replace(' ', 'T')).getTime() >= Date.now();
}
function membershipLabel(account = {}) {
  if (!isMembershipActive(account)) return 'Sin membresía';
  return String(account.membership_type).toLowerCase() === 'platinum' ? 'Platinum' : 'Gold';
}
function membershipClass(account = {}) {
  if (!isMembershipActive(account)) return '';
  return String(account.membership_type).toLowerCase() === 'platinum' ? 'membership-platinum' : 'membership-gold';
}
