function dynamicTx(text, lang = 'es') {
  if (lang === 'es' || !text) return text;
  return (DYNAMIC_TRANSLATION_PATTERNS[lang] || []).reduce((acc, [rx, repl]) => acc.replace(rx, repl), String(text));
}

const ORIGINAL_TEXT_NODES = new WeakMap();
function translateElementTree(root, lang = 'es') {
  if (!root || lang === 'es') return;
  const dict = UI_TEXT[lang] || {};
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      const parent = node.parentElement;
      if (!parent || ['SCRIPT','STYLE','TEXTAREA','INPUT'].includes(parent.tagName)) return NodeFilter.FILTER_REJECT;
      return node.nodeValue && node.nodeValue.trim() ? NodeFilter.FILTER_ACCEPT : NodeFilter.FILTER_REJECT;
    }
  });
  const nodes = [];
  while (walker.nextNode()) nodes.push(walker.currentNode);
  for (const node of nodes) {
    if (!ORIGINAL_TEXT_NODES.has(node)) ORIGINAL_TEXT_NODES.set(node, node.nodeValue);
    const original = ORIGINAL_TEXT_NODES.get(node);
    const trimmed = original.trim();
    const translated = dict[trimmed];
    if (translated) node.nodeValue = original.replace(trimmed, translated);
    else { const dyn = dynamicTx(original, lang); if (dyn !== original) node.nodeValue = dyn; }
  }
  root.querySelectorAll?.('[placeholder], [title], [aria-label]').forEach((el) => {
    for (const attr of ['placeholder','title','aria-label']) {
      if (!el.hasAttribute(attr)) continue;
      const dataKey = `qlOriginal${attr.replace(/(^|-)(\w)/g,(_,a,b)=>b.toUpperCase())}`;
      if (!el.dataset[dataKey]) el.dataset[dataKey] = el.getAttribute(attr);
      const original = el.dataset[dataKey];
      if (dict[original]) el.setAttribute(attr, dict[original]);
      else { const dyn = dynamicTx(original, lang); if (dyn !== original) el.setAttribute(attr, dyn); }
    }
  });
}
function appPrefs(account = {}) { return { language:'es', theme:'light', app_size:'normal', ...(account?.preferences?.app || {}) }; }
function tx(text, lang = 'es') { return UI_TEXT[lang]?.[text] || dynamicTx(String(text ?? ''), lang) || text; }
function useAppChromePrefs(account) {
  useEffect(() => {
    const prefs = appPrefs(account);
    const lang = prefs.language || 'es';
    document.documentElement.dataset.theme = prefs.theme || 'light';
    document.documentElement.dataset.appSize = prefs.app_size || 'normal';
    document.documentElement.lang = lang;
    const translateNow = () => translateElementTree(document.body, lang);
    requestAnimationFrame(translateNow);
    const observer = new MutationObserver(() => requestAnimationFrame(translateNow));
    observer.observe(document.body, { childList:true, subtree:true });
    return () => observer.disconnect();
  }, [account?.preferences_json, account?.preferences?.app?.language, account?.preferences?.app?.theme, account?.preferences?.app?.app_size]);
}
function membershipFeeDiscount(account = {}, restaurantId = null) {
  if (!isMembershipActive(account)) return 0;
  const type = String(account.membership_type).toLowerCase();
  if (type === 'platinum') return 0.5;
  if (type === 'gold' && Number(account.membership_restaurant_id || 0) === Number(restaurantId || 0)) return 1;
  return 0;
}
function membershipAccent(account = {}) {
  if (!isMembershipActive(account)) return '';
  return String(account.membership_type).toLowerCase() === 'platinum' ? 'Platinum' : 'Gold';
}

function goldLunchesLeft(account = {}, credits = [], restaurants = []) {
  const rid = Number(account?.membership_restaurant_id || 0);
  if (!rid) return null;
  const credit = asArray(credits).filter(c => Number(c.restaurant_id || 0) === rid).reduce((s,c)=>s+Number(c.balance||0),0);
  const rest = asArray(restaurants).find(r => Number(r.id) === rid);
  const base = Number(rest?.base_lunch_price || rest?.baseLunchPrice || 15000);
  return { credit, base, lunches: base > 0 ? Math.floor(credit / base) : 0, restaurant: rest };
}


async function api(path, options = {}) {
  const token = localStorage.getItem('ql_token');
  let finalPath = path;
  const restaurantSlug = localStorage.getItem('ql_restaurant_slug');
  if (restaurantSlug && finalPath.startsWith('/restaurant/') && !finalPath.includes('slug=')) {
    finalPath += `${finalPath.includes('?') ? '&' : '?'}slug=${encodeURIComponent(restaurantSlug)}`;
  }
  const headers = { ...(options.body instanceof FormData ? {} : { 'Content-Type': 'application/json' }), ...(token ? { Authorization: `Bearer ${token}` } : {}), ...(options.headers || {}) };
  let res;
  try {
    res = await fetch(`${API_URL}${finalPath}`, { ...options, headers });
  } catch (error) {
    throw new Error('No se pudo conectar con el servidor de QuickLunch. Verifica que el backend esté encendido en http://localhost:4000 y que no se haya caído por una base vieja.');
  }
  const text = await res.text();
  let data = {};
  try { data = text ? JSON.parse(text) : {}; } catch { data = { raw: text }; }
  if (!res.ok) throw new Error(data.message || 'Error de QuickLunch');
  return data;
}

class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { error: null }; }
  static getDerivedStateFromError(error) { return { error }; }
  render() {
    if (this.state.error) return <div className="panic card"><AlertTriangle /><h2>No se pudo cargar esta pantalla</h2><p>{this.state.error.message}</p><button className="primary-btn" onClick={() => location.reload()}>Recargar pantalla</button></div>;
    return this.props.children;
  }
}

function AuthProvider({ children }) {
  const [account, setAccount] = useState(() => JSON.parse(localStorage.getItem('ql_account') || 'null'));
  const [booting, setBooting] = useState(!!localStorage.getItem('ql_token'));
  useEffect(() => {
    if (!localStorage.getItem('ql_token')) return setBooting(false);
    api('/me').then((me) => { localStorage.setItem('ql_account', JSON.stringify(me)); setAccount(me); }).catch(() => { localStorage.removeItem('ql_token'); localStorage.removeItem('ql_account'); setAccount(null); }).finally(() => setBooting(false));
  }, []);
  const save = (payload) => { localStorage.setItem('ql_token', payload.token); localStorage.setItem('ql_account', JSON.stringify(payload.account)); setAccount(payload.account); };
  const logout = () => { localStorage.removeItem('ql_token'); localStorage.removeItem('ql_account'); setAccount(null); };
  return <AuthContext.Provider value={{ account, save, logout, booting, refresh: () => api('/me').then((me)=>{ localStorage.setItem('ql_account', JSON.stringify(me)); setAccount(me); return me; }) }}>{children}</AuthContext.Provider>;
}
function useAuth() { return useContext(AuthContext); }

function Loading({ label = 'Cargando QuickLunch...' }) { return <div className="loading-card"><RefreshCw className="spin" /><strong>{label}</strong><span>Si tu internet está lento, la app reintenta sin dejar la pantalla en blanco.</span></div>; }
function Toast({ message, type = 'info', onClose }) { if (!message) return null; return <div className={`toast ${type}`} onClick={onClose}>{message}</div>; }

function useSystemStatus() {
  const [status, setStatus] = useState({ online: navigator.onLine, api: 'checking', last: '' });
  useEffect(() => {
    let active = true;
    const check = async () => {
      try {
        const r = await fetch(`${API_URL}/health`, { cache: 'no-store' });
        if (!active) return;
        setStatus({ online: navigator.onLine, api: r.ok ? 'ok' : 'error', last: new Date().toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit' }) });
      } catch {
        if (active) setStatus({ online: navigator.onLine, api: 'error', last: new Date().toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit' }) });
      }
    };
    check();
    const id = setInterval(check, 20000);
    const on = () => check();
    window.addEventListener('online', on);
    window.addEventListener('offline', on);
    return () => { active = false; clearInterval(id); window.removeEventListener('online', on); window.removeEventListener('offline', on); };
  }, []);
  return status;
}

function SystemStatusBar({ compact = false }) {
  const status = useSystemStatus();
  const { account } = useAuth() || {};
  const lang = appPrefs(account).language || 'es';
  const ok = status.online && status.api === 'ok';
  return <div className={`system-status ${ok ? 'ok' : 'warn'} ${compact ? 'compact' : ''}`}>
    <span>{ok ? tx('Sistema en línea', lang) : tx('Conexión inestable', lang)}</span>
    <small>{ok ? tx('Cambios, pedidos y soporte se sincronizan con QuickLunch.', lang) : tx('Revisa que el servidor esté abierto y que estés en la misma red WiFi.', lang)} {status.last && `${tx('Última verificación', lang)}: ${status.last}`}</small>
  </div>;
}

