function StarRating({ rating }) { const avg=Number(rating?.average||0); const count=Number(rating?.count||0); const display=Math.floor(avg*2)/2; const parts=[1,2,3,4,5].map(n=> display>=n?'★':display>=n-0.5?'⯪':'☆'); return <span className="stars-display" title={`${avg.toFixed(2)} de 5`}>{parts.join(' ')} <small>({count})</small></span>; }

