function LoginCard({ target = 'customer', title, subtitle, allowRegister = false }) {
  const { save } = useAuth();
  const navigate = useNavigate();
  const [city, setCity] = useState('Cali');
  const [form, setForm] = useState({ username: '', password: '' });
  const [msg, setMsg] = useState('');
  const [register, setRegister] = useState(false);
  const [restaurantApply, setRestaurantApply] = useState(false);
  const [recover, setRecover] = useState(false);
  const [recoveryResult, setRecoveryResult] = useState(null);
  const [recoverId, setRecoverId] = useState('');
  const [newUser, setNewUser] = useState({ full_name: '', username: '', email: '', phone: '', password: '', consent_analytics: true });
  const emptyApplication = Object.fromEntries(LEGAL_FIELDS.map((f) => [f, '']));
  const [application, setApplication] = useState({ ...emptyApplication, city: 'Cali' });
  const checkRole = (role) => {
    if (role === 'owner') return true;
    if (target === 'admin') return role === 'admin';
    if (target === 'restaurant') return ['restaurant_owner', 'restaurant_staff'].includes(role);
    if (target === 'customer') return isCustomerAccessRole(role);
    return true;
  };
  const login = async (e) => {
    e.preventDefault(); setMsg('');
    try {
      if (city !== 'Cali') throw new Error('Ciudad próximamente disponible.');
      const payload = await api('/auth/login', { method: 'POST', body: JSON.stringify({ ...form, city }) });
      if (!checkRole(payload.account.role)) throw new Error('Tu rol no tiene acceso a esta plataforma.');
      save(payload);
    } catch (err) { setMsg(err.message); }
  };
  const submitRegister = async (e) => {
    e.preventDefault(); setMsg('');
    try { const payload = await api('/auth/register', { method: 'POST', body: JSON.stringify(newUser) }); save(payload); }
    catch (err) { setMsg(err.message); }
  };
  const submitApplication = async (e) => {
    e.preventDefault(); setMsg('');
    try {
      const r = await api('/restaurants/apply', { method: 'POST', body: JSON.stringify({ ...application, city: 'Cali' }) });
      setMsg(`${r.message} URL solicitada: /${r.requested_slug}. Nos comunicaremos con usted para más información.`);
      setRestaurantApply(false);
    } catch (err) { setMsg(err.message); }
  };
  const submitRecovery = async () => {
    setRecoveryResult(null); setMsg('');
    try { setRecoveryResult(await api('/auth/password-recovery', { method: 'POST', body: JSON.stringify({ identifier: recoverId }) })); }
    catch (err) { setMsg(err.message); }
  };
  const handleLoginBack = () => { if (register) setRegister(false); else if (restaurantApply) setRestaurantApply(false); else navigate('/home'); };
  return <section className="login-shell">
    <button type="button" className="back-btn login-back" onClick={handleLoginBack}><ArrowLeft size={17}/> Regresar</button><UsabilityHelp/>
    <div className="login-card card glass"><Logo /><h1>{title}</h1><p>{subtitle}</p>
      <Field label="Ciudad activa"><select value={city} onChange={(e) => { if (e.target.value !== 'Cali') setMsg('Ciudad próximamente disponible.'); else { setCity(e.target.value); setMsg(''); } }}><option>Cali</option><option>Pasto</option><option>Bogotá</option></select></Field><InlineHelp>Usa ejemplos genéricos como user123 y password123. Las acciones importantes muestran confirmación o mensaje claro.</InlineHelp>
      {!register && !restaurantApply ? <form onSubmit={login} className="form-grid">
        <Input label="Usuario o correo" value={form.username} onChange={(v) => setForm({ ...form, username: v })} placeholder="Ej: user123 o usuario@email.com" />
        <Input type="password" label="Contraseña" value={form.password} onChange={(v) => setForm({ ...form, password: v })} placeholder="Ej: password123" />
        {msg && <p className={msg.includes('Solicitud enviada')?'success-msg':'error-msg'}>{msg}</p>}
        <button className="primary-btn">Ingresar</button>
      </form> : register ? <form onSubmit={submitRegister} className="form-grid">
        <Input label="Nombre completo" value={newUser.full_name} onChange={(v) => setNewUser({ ...newUser, full_name: v })} placeholder="Ej: Laura Gómez" />
        <Input label="Usuario" value={newUser.username} onChange={(v) => setNewUser({ ...newUser, username: v })} placeholder="Ej: user123" />
        <Input label="Correo para recuperación" value={newUser.email} onChange={(v) => setNewUser({ ...newUser, email: v })} placeholder="Ej: usuario@email.com" />
        <Input label="Celular" value={newUser.phone} onChange={(v) => setNewUser({ ...newUser, phone: v })} placeholder="Ej: 3001234567" />
        <Input type="password" label="Contraseña" value={newUser.password} onChange={(v) => setNewUser({ ...newUser, password: v })} placeholder="Ej: password123" />
        <Select label="Permiso para recomendaciones" value={newUser.consent_analytics ? 'yes' : 'no'} onChange={(v) => setNewUser({ ...newUser, consent_analytics: v === 'yes' })}>{YES_NO_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}</Select>
        {msg && <p className={msg.includes('Solicitud enviada')?'success-msg':'error-msg'}>{msg}</p>}
        <button className="primary-btn">Crear cuenta</button>
      </form> : <form onSubmit={submitApplication} className="form-grid admin-form">
        <p className="muted">Solicitud de registro del restaurante. QuickLunch la revisa desde el panel administrativo.</p>
        {LEGAL_FIELDS.map((f) => <Input key={f} type={f.includes('password')?'password':f.includes('until')?'date':'text'} label={fieldLabel(f)} placeholder={placeholder(f)} value={application[f]} onChange={(v) => setApplication({ ...application, [f]: v })}/>) }
        {msg && <p className={msg.includes('Solicitud enviada')?'success-msg':'error-msg'}>{msg}</p>}
        <button className="primary-btn">Enviar solicitud de restaurante</button>
      </form>}
      <div className="login-actions">
        {allowRegister && <button className="ghost-btn" onClick={() => { setRegister(!register); setRestaurantApply(false); }}>{register ? 'Ya tengo cuenta' : 'Crear cuenta de cliente'}</button>}
        {target === 'restaurant' && <button className="ghost-btn" onClick={() => { setRestaurantApply(!restaurantApply); setRegister(false); }}>{restaurantApply ? 'Volver al login' : 'Registro de restaurante'}</button>}
        <button className="ghost-btn" type="button" onClick={() => setRecover(true)}>Recuperar contraseña</button>
      </div>
    </div>
    {recover && <Modal title="Recuperación piloto de contraseña" onClose={() => { setRecover(false); setRecoveryResult(null); }}><div className="form-grid"><p>Versión piloto: escribe únicamente el usuario y QuickLunch consulta la base local para mostrar la clave en pantalla.</p><Input label="Usuario" value={recoverId} onChange={setRecoverId} placeholder="Ej: user123"/><button className="primary-btn" onClick={submitRecovery}>Mostrar clave piloto</button>{recoveryResult && <div className="success-msg"><b>{recoveryResult.message}</b><p>Usuario: {recoveryResult.username}</p><p>Correo asociado: {recoveryResult.recovery_email}</p><p><b>Clave:</b> {recoveryResult.visible_password}</p></div>}{msg && <p className="error-msg">{msg}</p>}</div></Modal>}
  </section>;
}

function Shell({ nav, children, mode = 'desktop' }) {
  const { account, logout } = useAuth();
  useAppChromePrefs(account);
  const prefs = appPrefs(account); const lang = prefs.language || 'es';
  return <div className={`app-shell ${mode}`}>
    <aside className="sidebar"><Logo /><nav>{nav.map((n) => <Link key={n.to} to={n.to}><n.icon size={18}/>{tx(n.label, lang)}</Link>)}</nav><button className="ghost-btn" onClick={logout}><LogOut size={18}/> {tx('Cerrar sesión', lang)}</button></aside>
    <main className="content-area"><header className="topbar"><BackButton label={tx('Regresar', lang)} fallback="/home"/><div><p>Hola, {account?.full_name || account?.username}</p><h2>{ROLE_LABELS[account?.role] || account?.role}</h2></div><Badge>{account?.role_label || ROLE_LABELS[account?.role]}</Badge></header><SystemStatusBar/><UsabilityHelp/>{children}</main>
  </div>;
}

function useLoad(loader, deps = []) {
  const [data, setData] = useState(null); const [error, setError] = useState(''); const [loading, setLoading] = useState(true);
  const run = (silent = false) => { if (!silent) setLoading(true); setError(''); return Promise.resolve(loader()).then(setData).catch((e) => setError(e.message)).finally(() => setLoading(false)); };
  useEffect(() => { run(false); }, deps);
  return { data, setData, error, loading, reload: (silent = true) => run(silent) };
}

