function AdminCoupons() {
  const { data: rawCoupons=[], loading, reload } = useLoad(()=>api('/admin/coupons'),[]);
  const { data: rawUsers=[] } = useLoad(()=>api('/admin/users'),[]);
  const { data: rawRestaurants=[] } = useLoad(()=>api('/admin/restaurants'),[]);
  const coupons=asArray(rawCoupons), users=asArray(rawUsers), restaurants=asArray(rawRestaurants);
  const blank={ kind:'coupon', code:'', starts_at:nowLocalInput(), ends_at:'', unlimited_uses:false, max_uses:100, effect_scope:'app', effect_type:'credit_fixed', effect_value:5000, coverage_restaurants:[], auto_apply:false, all_users:true, user_ids:[], is_promotion:true };
  const [form,setForm]=useState(blank); const [edit,setEdit]=useState(null); const [msg,setMsg]=useState(''); const [usage,setUsage]=useState(null);
  const current=edit||form; const setCurrent=(next)=>edit?setEdit(next):setForm(next);
  const save=async(e)=>{ e?.preventDefault?.(); setMsg(''); try{ const path=edit?`/admin/coupons/${edit.id}`:'/admin/coupons'; const method=edit?'PATCH':'POST'; await api(path,{method,body:JSON.stringify(current)}); setMsg(edit?'Beneficio actualizado.':'Beneficio creado.'); setEdit(null); setForm(blank); reload(); }catch(err){setMsg(err.message)} };
  const remove=async(c)=>{ if(!confirm(`¿Eliminar ${c.code}?`))return; try{ const r=await api(`/admin/coupons/${c.id}`,{method:'DELETE'}); setMsg(r.message); reload(); }catch(e){setMsg(e.message)} };
  const showUsage=async(c)=>{ try{setUsage(await api(`/coupons/${c.id}/usages`));}catch(e){setMsg(e.message)} };
  const formBlock=<form className="form-grid admin-form" onSubmit={save}><Select label="Tipo" value={current.kind} onChange={(v)=>setCurrent({...current,kind:v})}><option value="coupon">Cupón redimible</option><option value="discount">Descuento automático</option></Select>{current.kind==='coupon'&&<Input label="ID / nombre del cupón" value={current.code} onChange={(v)=>setCurrent({...current,code:v.toUpperCase()})} placeholder="Ej: QL5000"/>}<Input type="datetime-local" label="Inicio de vigencia" value={current.starts_at} onChange={(v)=>setCurrent({...current,starts_at:v})}/><Input type="datetime-local" label="Fin de vigencia" value={current.ends_at} onChange={(v)=>setCurrent({...current,ends_at:v})}/><Select label="Usos ilimitados" value={current.unlimited_uses?'yes':'no'} onChange={(v)=>setCurrent({...current,unlimited_uses:v==='yes'})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>{!current.unlimited_uses&&<Input label="Cantidad de usos" value={current.max_uses} onChange={(v)=>setCurrent({...current,max_uses:Number(v)})}/>}<Select label="Cobertura" value={current.effect_scope} onChange={(v)=>setCurrent({...current,effect_scope:v})}><option value="app">Toda QuickLunch</option><option value="restaurant">Un restaurante o grupo</option></Select>{current.effect_scope==='restaurant'&&<div className="product-picker">{restaurants.map(r=><label key={r.id} className="check-row"><input type="checkbox" checked={asArray(current.coverage_restaurants).map(Number).includes(Number(r.id))} onChange={(e)=>{ const set=new Set(asArray(current.coverage_restaurants).map(Number)); e.target.checked?set.add(Number(r.id)):set.delete(Number(r.id)); setCurrent({...current,coverage_restaurants:[...set]}); }}/>{r.name}</label>)}</div>}<Select label="Efecto" value={current.effect_type} onChange={(v)=>setCurrent({...current,effect_type:v})}><option value="credit_fixed">Créditos / saldo</option><option value="discount_fixed">Saldo descontable</option><option value="discount_percent">Descuento %</option><option value="service_free">Servicio gratis</option><option value="service_percent">Descuento en servicio %</option></Select>{current.effect_type!=='service_free'&&<Input label="Valor del efecto" value={current.effect_value} onChange={(v)=>setCurrent({...current,effect_value:Number(v)})}/>}<Select label="Aplicación automática" value={current.auto_apply?'yes':'no'} onChange={(v)=>setCurrent({...current,auto_apply:v==='yes'})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>{current.auto_apply&&<Select label="Beneficiar usuarios" value={current.all_users?'all':'selected'} onChange={(v)=>setCurrent({...current,all_users:v==='all'})}><option value="all">Todos los clientes</option><option value="selected">Usuarios seleccionados</option></Select>}{current.auto_apply&&!current.all_users&&<div className="product-picker">{users.filter(u=>u.role==='customer').map(u=><label key={u.id} className="check-row"><input type="checkbox" checked={asArray(current.user_ids).map(Number).includes(Number(u.id))} onChange={(e)=>{ const set=new Set(asArray(current.user_ids).map(Number)); e.target.checked?set.add(Number(u.id)):set.delete(Number(u.id)); setCurrent({...current,user_ids:[...set]}); }}/>{u.username} · {u.full_name}</label>)}</div>}<button className="primary-btn">{edit?'Guardar cambios':'Crear beneficio'}</button>{edit&&<button type="button" className="ghost-btn" onClick={()=>setEdit(null)}>Cancelar edición</button>}</form>;
  if(loading)return <Loading/>; return <div className="page-grid"><section className="card"><h3>{edit?'Modificar beneficio':'Cupones, créditos y descuentos globales'}</h3>{formBlock}{msg&&<p className={msg.includes('creado')||msg.includes('actualizado')||msg.includes('eliminado')?'success-msg':'error-msg'}>{msg}</p>}</section><section className="card"><h3>Beneficios existentes</h3>{coupons.map(c=><article className="coupon" key={c.id}><b>{c.code}</b><p>{c.promotionBadge || c.name} · {c.restaurant_name||'Toda QuickLunch'} · creado por {c.created_by}</p><span>{c.is_redeemable?'Cupón':'Descuento'} · {c.active?'Activo':'Inactivo'}</span><div className="actions"><button onClick={()=>setEdit({...c,kind:c.is_redeemable?'coupon':'discount',starts_at:(c.starts_at||'').replace(' ','T'),ends_at:(c.ends_at||'').replace(' ','T'),unlimited_uses:!!c.unlimited_uses,coverage_restaurants:asArray(c.coverageRestaurants),auto_apply:!!c.auto_apply,all_users:true,user_ids:[]})}><Edit3 size={15}/> Modificar</button><button onClick={()=>showUsage(c)}><UsersRound size={15}/> Usos</button><button className="danger-btn" onClick={()=>remove(c)}><Trash2 size={15}/> Eliminar</button></div></article>)}</section>{usage&&<Modal title="Usuarios que usaron el beneficio" onClose={()=>setUsage(null)}><p>Total de usos: <b>{usage.total}</b></p><Table headers={["Usuario","Hora","Tipo","Monto"]} rows={asArray(usage.usages).map(u=>[u.user?.username||'Usuario',u.created_at,u.usage_type,money(u.amount)])}/></Modal>}</div>;
}
function AdminApplications() {
  const { account } = useAuth();
  const { data: raw = [], loading, reload } = useLoad(() => api('/admin/applications'), []);
  const apps = asArray(raw);
  const [selected, setSelected] = useState(null);
  const [notes, setNotes] = useState('');
  const [msg, setMsg] = useState('');
  const canDecide = account.role === 'owner';
  const decide = async (id, status) => {
    setMsg('');
    try {
      const r = await api(`/admin/applications/${id}`, { method:'PATCH', body:JSON.stringify({ status, reviewer_notes: notes }) });
      setMsg(r.message || 'Solicitud actualizada.');
      setSelected(null); setNotes(''); reload();
    } catch (e) { setMsg(e.message); }
  };
  if (loading) return <Loading/>;
  return <section className="card"><div className="section-head"><div><h3>Solicitudes legales de restaurantes</h3><p>Revisa la información completa antes de aprobar o rechazar. La decisión final queda habilitada para owner.</p></div></div>{msg && <p className={msg.includes('aprobado')||msg.includes('actualizada')?'success-msg':'error-msg'}>{msg}</p>}{apps.length===0 && <Empty text="No hay solicitudes de restaurantes."/>}{apps.map((a) => <article className="list-card" key={a.id}><div><h4>{a.legal?.name || 'Restaurante sin nombre'}</h4><p>{a.legal?.address || 'Sin dirección'} · NIT/RUT: {a.legal?.nit || 'Sin dato'}</p><p>Estado: <b>{a.status}</b> · Slug solicitado: /{a.requested_slug || 'pendiente'}</p></div><div className="actions"><button className="secondary-btn" onClick={() => { setSelected(a); setNotes(a.reviewer_notes || ''); }}><ShieldCheck size={15}/> Revisar detalle</button></div></article>)}{selected && <Modal title={`Revisión legal: ${selected.legal?.name || 'Solicitud'}`} onClose={() => setSelected(null)}><div className="detail-grid"><p><b>Nombre comercial:</b> {selected.legal?.name || 'Sin dato'}</p><p><b>Dueño:</b> {selected.legal?.owner_name || 'Sin dato'}</p><p><b>Representante legal:</b> {selected.legal?.legal_representative || selected.legal?.owner_name || 'Sin dato'}</p><p><b>Documento dueño:</b> {selected.legal?.owner_document || 'Sin dato'}</p><p><b>NIT/RUT:</b> {selected.legal?.nit || 'Sin dato'}</p><p><b>Correo:</b> {selected.legal?.email || 'Sin dato'}</p><p><b>Teléfono:</b> {selected.legal?.phone || 'Sin dato'}</p><p><b>Dirección:</b> {selected.legal?.address || 'Sin dato'}</p><p><b>Matrícula mercantil / Cámara de Comercio:</b> {selected.legal?.chamber_commerce || 'Sin dato'}</p><p><b>RUT:</b> {selected.legal?.rut || 'Sin dato'}</p><p><b>Concepto sanitario:</b> {selected.legal?.sanitary_concept || 'Sin dato'}</p><p><b>Certificado de Bomberos:</b> {selected.legal?.firefighter_certificate || 'Sin dato'}</p><p><b>Uso del suelo:</b> {selected.legal?.land_use_concept || 'Sin dato'}</p><p><b>Aviso / registro ante autoridad:</b> {selected.legal?.police_opening_notice || 'Sin dato'}</p><p><b>Manipulación de alimentos:</b> {selected.legal?.food_handler_certificates || 'Sin dato'}</p><p><b>Política de datos personales:</b> {selected.legal?.personal_data_policy_url || 'Sin dato'}</p><p><b>Vigencia de asociación solicitada:</b> {selected.legal?.association_valid_until || 'Sin dato'}</p></div><label className="field full"><span>Notas de revisión</span><textarea value={notes} onChange={(e)=>setNotes(e.target.value)} placeholder="Ej: documentación completa, falta concepto sanitario, datos por validar..."/></label>{selected.status==='pending' ? <div className="actions"><button className="primary-btn" disabled={!canDecide} onClick={() => decide(selected.id,'approved')}>Aprobar restaurante</button><button className="danger-btn" disabled={!canDecide} onClick={() => decide(selected.id,'rejected')}>Rechazar solicitud</button>{!canDecide && <p className="error-msg">Solo un owner puede aprobar o rechazar solicitudes.</p>}</div> : <p className="muted">Esta solicitud ya fue revisada: {selected.status}.</p>}</Modal>}</section>;
}
function AdminSettings() { const { account } = useAuth(); const { data, loading, reload } = useLoad(() => api('/settings'), []); const [fees, setFees] = useState(null); useEffect(() => { if (data) setFees({ platinumPrice:16900, goldDiscountPercent:30, ...data.fees }); }, [data]); const save = async () => { await api('/admin/settings', { method:'PATCH', body:JSON.stringify({ fees }) }); reload(); }; if (loading || !fees) return <Loading/>; return <section className="card"><h3>Tarifas base QuickLunch</h3><p>Solo el owner puede cambiar las tarifas globales. Cada restaurante nace con estas tarifas, salvo que se le configure una tarifa especial.</p>{account.role !== 'owner' && <p className="error-msg">Tu rol puede ver esta sección, pero no modificar las tarifas.</p>}<div className="form-grid"><Input label="Pago digital por almuerzo" value={fees.online} onChange={(v) => setFees({ ...fees, online:Number(v) })}/><Input label="Pago en caja por almuerzo" value={fees.cash} onChange={(v) => setFees({ ...fees, cash:Number(v) })}/><Input label="Comisión porcentual QuickLunch" value={fees.commissionPercent} onChange={(v) => setFees({ ...fees, commissionPercent:Number(v) })}/><Input label="Precio membresía Platinum" value={fees.platinumPrice} onChange={(v) => setFees({ ...fees, platinumPrice:Number(v) })}/><Input label="Descuento base Gold (%)" value={fees.goldDiscountPercent} onChange={(v) => setFees({ ...fees, goldDiscountPercent:Number(v) })}/><button className="primary-btn" disabled={account.role !== 'owner'} onClick={save}>Guardar tarifas base</button></div></section>; }

function Modal({ title, children, onClose }) { return <div className="modal-backdrop"><div className="modal card"><button className="close" onClick={onClose}>×</button><h3>{title}</h3>{children}</div></div>; }

// RESTAURANT
function RestaurantApp() {
  const { slug } = useParams(); const { account, booting } = useAuth();
  useEffect(() => { if (slug) localStorage.setItem('ql_restaurant_slug', slug); }, [slug]);
  if (booting) return <Loading/>;
  if (!account || !canRestaurant(account.role)) return <LoginCard target="restaurant" title={`Gestión del restaurante${slug ? ` /${slug}` : ''}`} subtitle="Ingreso para dueños, cajeros y operadores autorizados por el restaurante." />;
  const nav = [{ to:`/${slug || 'restaurante'}`, icon:LayoutDashboard, label:'Inicio' }, { to:`/${slug || 'restaurante'}/inventario`, icon:PackagePlus, label:'Inventario' }, { to:`/${slug || 'restaurante'}/menu`, icon:ChefHat, label:'Menú del día' }, { to:`/${slug || 'restaurante'}/pedidos`, icon:QrCode, label:'Pedidos y códigos' }, { to:`/${slug || 'restaurante'}/historico`, icon:ClipboardList, label:'Histórico' }];
  if (canFullRestaurant(account.role)) nav.push({ to:`/${slug || 'restaurante'}/analitica`, icon:BarChart3, label:'Analítica' }, { to:`/${slug || 'restaurante'}/perfil`, icon:Settings, label:'Perfil y horarios' }, { to:`/${slug || 'restaurante'}/preview`, icon:Search, label:'Vista cliente' }, { to:`/${slug || 'restaurante'}/cupones`, icon:Gift, label:'Cupones y promos' }, { to:`/${slug || 'restaurante'}/equipo`, icon:UsersRound, label:'Equipo' }, { to:`/${slug || 'restaurante'}/soporte`, icon:MessageCircle, label:'Soporte' }, { to:`/${slug || 'restaurante'}/cuenta`, icon:UserRound, label:'Cuenta' });
  else nav.push({ to:`/${slug || 'restaurante'}/cuenta`, icon:UserRound, label:'Cuenta' });
  return <Shell nav={nav}><Routes><Route index element={<RestaurantDashboard/>}/><Route path="inventario" element={<Inventory/>}/><Route path="menu" element={<MenuBuilder/>}/><Route path="pedidos" element={<LiveOrders/>}/><Route path="historico" element={<RestaurantOrderHistory/>}/><Route path="analitica" element={<RestaurantAnalyticsPage/>}/><Route path="perfil" element={<RestaurantProfile/>}/><Route path="preview" element={<RestaurantPreview/>}/><Route path="cupones" element={<RestaurantCoupons/>}/><Route path="equipo" element={<RestaurantStaff/>}/><Route path="soporte" element={<SupportPanel/>}/><Route path="cuenta" element={<PlatformAccount/>}/></Routes></Shell>;
}
function useRestaurant() { return useLoad(() => api('/restaurant/me'), []); }
function RestaurantDashboard() { const { account } = useAuth(); const { data: me, loading } = useRestaurant(); const { data: analytics, loading: l2 } = useLoad(() => canFullRestaurant(account.role) ? api('/restaurant/analytics') : Promise.resolve(null), [account.role]); if (loading || l2) return <Loading/>; if (!me?.restaurant) return <Empty text="No hay restaurante asociado."/>; const r = me.restaurant; return <div className="page-grid"><section className="hero-card"><div><span className="eyebrow">/{r.slug}</span><h1>{r.name}</h1><p>{canFullRestaurant(account.role) ? 'Tienes acceso completo al restaurante.' : 'Rol operativo: puedes gestionar menú, pedidos y códigos, sin ver ingresos ni estadísticas.'}</p></div>{r.design?.logoUrl ? <img className="hero-logo" src={asset(r.design.logoUrl)}/> : <ChefHat size={80}/>}</section>{canFullRestaurant(account.role) && analytics && <><div className="stats-grid"><Stat icon={ShoppingBag} label="Pedidos" value={analytics.summary.orders}/><Stat icon={DollarSign} label="Liberado por código" value={money(analytics.summary.released)}/><Stat icon={WalletCards} label="Retenido hasta código" value={money(analytics.pendingHeld)} hint="Solo ganancia del restaurante"/><Stat icon={Star} label="Calificación" value={`${analytics.restaurant.rating?.average || 0}/5`} hint={`${analytics.restaurant.rating?.count || 0} pedidos`}/><Stat icon={Star} label="Puntos" value={analytics.restaurant.prestige_points}/></div><section className="card"><h3>IA operativa integrada</h3><p>Monitorea pedidos, pagos retenidos, códigos reclamados, incidencias y preferencias del restaurante.</p><ul className="check-list">{analytics.aiTips.map((t) => <li key={t}>{t}</li>)}</ul></section></>}</div>; }
function Inventory() {
  const { data: rawItems = [], loading, reload } = useLoad(() => api('/restaurant/inventory'), []);
  const items = asArray(rawItems).filter((x) => Number(x.active) !== 0);
  const blank = { category:'protein', name:'', description:'', stock:0, is_special:false, additional_cost:0, price:0, image_url:'', image_source:'none' };
  const [form, setForm] = useState(blank);
  const [editing, setEditing] = useState(null);
  const [suggestions, setSuggestions] = useState([]);
  const [msg,setMsg]=useState('');
  const [busy,setBusy]=useState(false);
  const uploadFile = async (file) => { const fd = new FormData(); fd.append('image', file); const res = await api('/restaurant/upload', { method:'POST', body: fd }); setForm({ ...form, image_url: res.url, image_source:'subida' }); };
  const suggest = async () => { setMsg(''); if (!form.name) return setMsg('Escribe el nombre del producto para buscar imágenes.'); setBusy(true); try { const r = await api(`/images/suggest?q=${encodeURIComponent(form.name)}&description=${encodeURIComponent(form.description || '')}`); const list = Array.isArray(r) ? r : asArray(r.images); setSuggestions(list); if(r?.help) setMsg(r.help); if(!list.length) setMsg('No se encontraron imágenes. Revisa el nombre o descripción.'); } catch(e) { setMsg(e.message); } finally { setBusy(false); } };
  const startEdit = (it) => { setEditing(it.id); setForm({ category:it.category, name:it.name, description:it.description||'', stock:it.stock||0, is_special:!!it.is_special, additional_cost:it.additional_cost||0, price:it.price||0, image_url:it.image_url||'', image_source:it.image_source||'none' }); setSuggestions([]); setMsg('Editando elemento. Guarda cambios o cancela.'); setTimeout(()=>window.scrollTo({top:0,behavior:'smooth'}),30); };
  const reset = () => { setEditing(null); setForm(blank); setSuggestions([]); setMsg(''); };
  const save = async (e) => { e.preventDefault(); setMsg(''); setBusy(true); try { const path = editing ? `/restaurant/inventory/${editing}` : '/restaurant/inventory'; const method = editing ? 'PATCH' : 'POST'; const r = await api(path, { method, body:JSON.stringify(form) }); setMsg(editing ? 'Elemento actualizado correctamente.' : 'Elemento guardado correctamente.'); reset(); reload(); } catch(e) { setMsg(e.message); } finally { setBusy(false); } };
  const remove = async (it) => { if(!confirm(`¿Eliminar ${it.name} del inventario?`)) return; try{ const r=await api(`/restaurant/inventory/${it.id}`,{method:'DELETE'}); setMsg(r.message || 'Elemento eliminado.'); reload(); }catch(e){ setMsg(e.message); } };
  if (loading) return <Loading/>; const grouped = items.reduce((a,x) => ({...a,[x.category]:[...(a[x.category]||[]),x]}),{});
  return <div className="page-grid"><section className="card"><h3>{editing ? 'Modificar alimento o plato' : 'Crear alimento o plato'}</h3><p>Los componentes no piden precio. Solo los especiales piden costo adicional. Los platos armados sí tienen precio propio.</p><form className="form-grid" onSubmit={save}><Select label="Tipo" value={form.category} onChange={(v)=>setForm({...form,category:v,is_special:false,additional_cost:0,price:0})}>{Object.entries(CATEGORY_LABELS).map(([k,v])=><option key={k} value={k}>{v}</option>)}</Select><Input label="Nombre" placeholder="Ej: Tilapia, lentejas, sopa de verduras" value={form.name} onChange={(v)=>setForm({...form,name:v})}/><Input label="Descripción" placeholder="Ej: porción crocante, receta casera, plato típico" value={form.description} onChange={(v)=>setForm({...form,description:v})}/>{form.category !== 'complete_plate' && <Select label="¿Es especial?" value={form.is_special ? 'yes' : 'no'} onChange={(v)=>setForm({...form,is_special:v==='yes', additional_cost:v==='yes'?form.additional_cost:0})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>}{form.category !== 'complete_plate' && form.is_special && <Input label="Costo adicional" value={form.additional_cost} onChange={(v)=>setForm({...form,additional_cost:Number(v)})}/>} {form.category === 'complete_plate' && <Input label="Precio propio del plato armado" value={form.price} onChange={(v)=>setForm({...form,price:Number(v)})}/>}<Field label="Imagen opcional"><input type="file" accept="image/*" onChange={(e)=> e.target.files?.[0] && uploadFile(e.target.files[0])}/></Field><p className="help-msg">¿Problemas en conseguir tu imagen? Asegúrate de haber escrito correctamente el producto y una descripción clara. QuickLunch filtra palabras inapropiadas y prioriza fotos de buena calidad.</p><button type="button" className="secondary-btn" disabled={busy} onClick={suggest}><Search size={16}/> {busy ? 'Buscando...' : 'Buscar 5 imágenes acordes'}</button>{suggestions.length>0 && <div className="suggestions">{suggestions.map((s,i)=><button type="button" key={`${s.url}-${i}`} className="suggestion" disabled={busy} onClick={async()=>{ setBusy(true); try { const imported = await api('/images/import',{method:'POST',body:JSON.stringify({url:s.url,thumbnail:s.thumbnail,label:s.label||form.name})}); setForm({...form,image_url:imported.url,image_source:s.source||'internet'}); setMsg(imported.message||'Imagen agregada al inventario.'); } catch(e) { setForm({...form,image_url:s.thumbnail||s.url,image_source:s.source||'internet'}); setMsg(e.message||'No se pudo importar, se usará el enlace original.'); } finally { setBusy(false); } }}><img src={asset(s.thumbnail||s.url)} onError={safeImg}/><span>Usar imagen {i+1}<small>{s.source}</small></span></button>)}</div>}{form.image_url && <img className="preview-img" src={asset(form.image_url)} onError={safeImg}/>}<div className="actions"><button className="primary-btn" disabled={busy}>{editing ? 'Guardar cambios' : 'Guardar alimento'}</button>{editing && <button type="button" className="ghost-btn" onClick={reset}>Cancelar edición</button>}</div>{msg && <p className={msg.includes('correctamente')||msg.includes('eliminado')?'success-msg':'error-msg'}>{msg}</p>}</form></section><section className="card"><h3>Inventario</h3>{Object.entries(grouped).map(([cat,arr])=><div key={cat}><h4>{categoryLabel(cat)}</h4>{arr.map((it)=><article className="ingredient-row" key={it.id}>{it.image_url ? <img src={asset(it.image_url)} onError={safeImg}/> : <ChefHat/>}<div><b>{it.name}</b><p>{it.is_special ? `Especial +${money(it.additional_cost)}` : it.category==='complete_plate' ? money(it.price) : 'Componente normal'} </p></div><div className="row-icons"><button title="Modificar" onClick={()=>startEdit(it)}><Edit3 size={16}/></button><button title="Eliminar" className="danger-icon" onClick={()=>remove(it)}><Trash2 size={16}/></button></div></article>)}</div>)}</section></div>;
}
function MenuBuilder() {
  const nav=useNavigate();
  const { data: inv = [], loading } = useLoad(() => api('/restaurant/inventory'), []);
  const { data: menusRaw = [], loading: loadingMenus, reload: reloadMenus } = useLoad(() => api('/restaurant/menus'), []);
  const blankMenu = { menu_date:today(), mode:'mixed', title:'Menú del día', base_price:15000, sell_soup_separately:true, soup_price:6000, sell_tray_separately:true, tray_price:13000, max_lunches_per_order:10, items:[] };
  const [form,setForm]=useState(blankMenu);
  const [loadedDate,setLoadedDate]=useState('');
  const [msg,setMsg]=useState('');
  const [busy,setBusy]=useState(false);
  const menus=asArray(menusRaw);
  const existing=menus.find(m=>m.menu_date===form.menu_date);

  useEffect(()=>{
    if (loadingMenus) return;
    if (loadedDate === form.menu_date) return;
    const m = asArray(menusRaw).find(x=>x.menu_date===form.menu_date);
    if (m) {
      setForm({
        menu_date:m.menu_date,
        mode:m.mode || 'mixed',
        title:m.title || 'Menú del día',
        base_price:Number(m.base_price || 15000),
        sell_soup_separately:!!Number(m.sell_soup_separately),
        soup_price:Number(m.soup_price || 6000),
        sell_tray_separately:!!Number(m.sell_tray_separately),
        tray_price:Number(m.tray_price || 13000),
        max_lunches_per_order:Number(m.max_lunches_per_order || 10),
        items:asArray(m.items).map(it=>({ inventory_item_id:it.inventory_item_id, category:it.category, name:it.name, stock:it.stock, price_delta:it.price_delta, price:it.price, is_special:it.is_special, image_url:it.image_url }))
      });
    }
    setLoadedDate(form.menu_date);
  },[loadingMenus, menusRaw, form.menu_date, loadedDate]);

  const changeDate=(v)=>{ setLoadedDate(''); const m=menus.find(x=>x.menu_date===v); if(!m) setForm({...blankMenu,menu_date:v}); else setForm({...form,menu_date:v}); };
  const toggle=(it)=>{ const exists=form.items.find(x=>Number(x.inventory_item_id)===Number(it.id)); setForm({...form,items: exists?form.items.filter(x=>Number(x.inventory_item_id)!==Number(it.id)):[...form.items,{ inventory_item_id:it.id, category:it.category, name:it.name, stock:10, price_delta:it.additional_cost, price:it.price, is_special:it.is_special, image_url:it.image_url }]});};
  const save=async()=>{ setBusy(true); setMsg(''); try{ const r=await api('/restaurant/menus',{method:'POST',body:JSON.stringify({...form,status:'published'})}); setMsg((r.message || (existing?'Menú modificado correctamente.':'Menú publicado correctamente.')) + ' Redirigiendo a Pedidos y códigos.'); reloadMenus(); setTimeout(()=>nav('../pedidos'),650); }catch(e){ setMsg(e.message); }finally{ setBusy(false); } };
  if(loading||loadingMenus)return <Loading/>;
  const activeInv=asArray(inv).filter(x=>Number(x.active)!==0);
  return <section className="card"><h3>{existing?'Modificar menú publicado':'Publicar menú del día'}</h3><p>{existing?'Ya existe un menú para esta fecha. QuickLunch no creará otro: solo guardará modificaciones sobre el menú existente.':'Solo se permite un menú por fecha. Cuando exista, este formulario lo modificará.'}</p><div className="form-grid"><Input label="Fecha" type="date" value={form.menu_date} onChange={changeDate}/><Input label="Título" value={form.title} onChange={(v)=>setForm({...form,title:v})}/><Input label="Precio almuerzo completo" value={form.base_price} onChange={(v)=>setForm({...form,base_price:Number(v)})}/><Select label="Vender sopa por separado" value={form.sell_soup_separately?'yes':'no'} onChange={(v)=>setForm({...form,sell_soup_separately:v==='yes'})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>{form.sell_soup_separately && <Input label="Precio sopa sola" value={form.soup_price} onChange={(v)=>setForm({...form,soup_price:Number(v)})}/>}<Select label="Vender bandeja por separado" value={form.sell_tray_separately?'yes':'no'} onChange={(v)=>setForm({...form,sell_tray_separately:v==='yes'})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>{form.sell_tray_separately && <Input label="Precio bandeja sola" value={form.tray_price} onChange={(v)=>setForm({...form,tray_price:Number(v)})}/>}<Input label="Máximo almuerzos por pedido" value={form.max_lunches_per_order} onChange={(v)=>setForm({...form,max_lunches_per_order:Math.min(10,Number(v))})}/></div><h4>Selecciona componentes y platos armados disponibles</h4><div className="inventory-pick">{activeInv.map((it)=><button key={it.id} className={form.items.find(x=>Number(x.inventory_item_id)===Number(it.id))?'selected':''} onClick={()=>toggle(it)}>{it.image_url?<img src={asset(it.image_url)} onError={safeImg}/>:<ChefHat/>}<span>{it.name}</span><small>{categoryLabel(it.category)}</small></button>)}</div>{form.items.length>0 && <section className="card stock-editor"><h4>Stock del menú publicado</h4><p>Define aquí el stock de cada elemento para este día. Este stock baja cuando el pedido queda entregado con código.</p>{form.items.map((mi,idx)=><div className="stock-row" key={`${mi.inventory_item_id}-${idx}`}><span>{mi.name} · {categoryLabel(mi.category)}</span><input type="number" min="0" value={mi.stock} onChange={(e)=>{ const copy=[...form.items]; copy[idx]={...copy[idx],stock:Number(e.target.value),remaining:Number(e.target.value)}; setForm({...form,items:copy}); }}/></div>)}</section>}<button className="primary-btn" disabled={busy || !form.items.length} onClick={save}>{busy?'Guardando...':existing?'Guardar modificación':'Publicar menú'}</button>{msg&&<p className={msg.includes('correctamente')?'success-msg':'error-msg'}>{msg}</p>}</section>;
}
function LiveOrders() { const { data, loading, reload } = useLoad(() => api('/restaurant/orders/live'), []); const [scanMsg,setScanMsg]=useState(''); useEffect(()=>{ const t=setInterval(()=>reload(true),2500); return()=>clearInterval(t); },[]); const [busy,setBusy]=useState(false); const setStatus=async(id,status)=>{ setBusy(true); try{ const r=await api(`/restaurant/orders/${id}/status`,{method:'PATCH',body:JSON.stringify({status})}); setScanMsg('Acción realizada: estado actualizado.'); reload(); }catch(e){ setScanMsg(e.message); }finally{ setBusy(false); } }; const scan=async(text)=>{ setBusy(true); try { const r=await api('/restaurant/orders/scan',{method:'POST',body:JSON.stringify({delivery_code:text})}); setScanMsg(r.message); reload(); } catch(e){ setScanMsg(e.message); } finally{ setBusy(false); } }; if(loading)return <Loading/>; const finalStatus=(o)=>['claimed','cancelled','no_show'].includes(o.status); const groups=Object.entries(data.groups||{}).map(([slot,orders])=>[slot,asArray(orders).sort((a,b)=>finalStatus(a)-finalStatus(b))]); return <div className="page-grid"><section className="card compact-card"><h3>Validación de código de entrega</h3><DeliveryCodeInput onScan={scan}/>{scanMsg && <p className={scanMsg.includes('Código validado')||scanMsg.includes('Acción realizada')?'success-msg':'notice'}>{scanMsg}</p>}</section><section className="card"><h3>Reservas agrupadas por franja</h3>{groups.length===0 && <Empty text="No hay pedidos para hoy."/>}{groups.map(([slot,orders])=><div className="slot-group" key={slot}><h4>{slot}</h4>{orders.map((o)=><article className={`order-card live-small ${['claimed','cancelled','no_show'].includes(o.status)?'claimed-order':''}`} key={o.id}>{['claimed','cancelled','no_show'].includes(o.status)&&<div className="claimed-cover">{o.status==='claimed'?'Entregado · código usado':'Finalizado / cancelado'}</div>}<div><b>Pedido #{o.id}</b> <Badge>{orderStatus(o.status)}</Badge><p>{o.customer_name} · {o.lunch_count} almuerzo(s) · {o.payment_method==='cash'?'Cobrar en caja':'Pago previo retenido'} · {money(o.total)}</p><ol>{asArray(o.items).map((l,i)=><li key={i}>{l.label || l.type}: {money(l.total)} {asArray(l.components).map(c=>c.name).join(', ')}</li>)}</ol></div><div className="actions">{['claimed','cancelled','no_show'].includes(o.status)?<Badge tone="success">Finalizado</Badge>:<><button disabled={busy||o.status==='preparing'} onClick={()=>setStatus(o.id,'preparing')}>Preparando</button><button disabled={busy||o.status==='ready'} onClick={()=>setStatus(o.id,'ready')}>Listo</button><button disabled={busy} onClick={()=>setStatus(o.id,'delayed')}>Demora</button><button disabled={busy} className="danger-btn" onClick={()=>setStatus(o.id,'cancelled')}>Cancelar</button></>}</div></article>)}</div>)}</section></div>; }
function DeliveryCodeInput({ onScan }) { const [digits,setDigits]=useState(['','','','','','']); const refs=useRef([]); const codeValue=digits.join('').replace(/(\d{3})(\d{0,3})/,'$1-$2'); const setDigit=(idx,value)=>{ const v=String(value).replace(/\D/g,'').slice(-1); const copy=[...digits]; copy[idx]=v; setDigits(copy); if(v && idx<5) refs.current[idx+1]?.focus(); }; const paste=(e)=>{ const nums=e.clipboardData.getData('text').replace(/\D/g,'').slice(0,6).split(''); if(nums.length){ e.preventDefault(); setDigits(Array.from({length:6},(_,i)=>nums[i]||'')); } }; return <div className="delivery-code-box"><p>Solicita al cliente su código de 6 dígitos. Formato:</p><div className="code-inputs" onPaste={paste}>{digits.map((d,i)=><React.Fragment key={i}><input ref={el=>refs.current[i]=el} inputMode="numeric" maxLength="1" value={d} onChange={(e)=>setDigit(i,e.target.value)} />{i===2&&<b>-</b>}</React.Fragment>)}</div><button className="primary-btn" disabled={digits.join('').length<6} onClick={()=>onScan(codeValue)}>Validar código</button></div>; }
function RestaurantOrderHistory(){
  const [filters,setFilters]=useState({q:'',status:'all',date:''});
  const query=`?q=${encodeURIComponent(filters.q)}&status=${encodeURIComponent(filters.status)}&date=${encodeURIComponent(filters.date)}`;
  const {data:raw=[],loading,error,reload}=useLoad(()=>api('/restaurant/orders/history'+query),[filters.q,filters.status,filters.date]);
  const rows=asArray(raw);
  if(loading)return <Loading/>;
  return <div className="page-grid"><section className="card"><div className="section-head"><div><h3>Histórico de pedidos completados</h3><p>Los pedidos entregados, cancelados o no reclamados salen de la vista en vivo y quedan guardados aquí.</p></div><button onClick={reload}><RefreshCw size={15}/> Actualizar</button></div>{error&&<p className="error-msg">{error}</p>}<div className="form-grid"><Input label="Buscar" value={filters.q} onChange={(v)=>setFilters({...filters,q:v})} placeholder="ID, cliente, código, estado..."/><Select label="Estado" value={filters.status} onChange={(v)=>setFilters({...filters,status:v})}><option value="all">Todos</option><option value="claimed">Entregados</option><option value="cancelled">Cancelados</option><option value="no_show">No reclamados</option></Select><Field label="Fecha"><input type="date" value={filters.date} onChange={(e)=>setFilters({...filters,date:e.target.value})}/></Field></div>{!rows.length&&<Empty text="No hay pedidos históricos con esos filtros."/>}{rows.map(o=><article className="order-card history-order" key={o.id}><div><b>Pedido #{o.id}</b> <Badge>{orderStatus(o.status)}</Badge><p>{o.customer_name} · {o.pickup_slot} · {o.lunch_count} almuerzo(s) · {money(o.total)}</p><ol>{asArray(o.items).map((l,i)=><li key={i}>{l.label || l.type}: {money(l.total)}</li>)}</ol></div><div><small>Pago: {o.payment_method==='cash'?'Caja':'Digital'}</small></div></article>)}</section></div>;
}

function RestaurantProfile() { const { data: me, loading, reload }=useRestaurant(); const [form,setForm]=useState(null); useEffect(()=>{ if(me?.restaurant) setForm({ profile:me.restaurant.profile||{}, design:me.restaurant.design||{}, settings:me.restaurant.settings||{} });},[me]); const upload=async(file,key)=>{ const fd=new FormData(); fd.append('image',file); const r=await api('/restaurant/upload',{method:'POST',body:fd}); setForm({...form,design:{...form.design,[key]:r.url}});}; const save=async()=>{ await api('/restaurant/profile',{method:'PUT',body:JSON.stringify(form)}); reload();}; if(loading||!form)return <Loading/>; const range=form.settings?.pickup?.ranges?.[0]||{start:'11:00',end:'14:00',intervalMinutes:10,capacity:10}; const setRange=(k,v)=>setForm({...form,settings:{...form.settings,pickup:{...(form.settings.pickup||{}),ranges:[{...range,[k]:v}]}}}); return <section className="card"><div className="section-head"><div><h3>Personalización, logo, banner y horarios</h3><p>Sube imágenes locales como en una red social. No necesitas URL.</p></div><Badge>Usa la pestaña Vista cliente sin abrir otra URL</Badge></div><div className="form-grid"><Input label="Descripción pública" value={form.profile.description} onChange={(v)=>setForm({...form,profile:{...form.profile,description:v}})}/><Field label="Logo del restaurante"><input type="file" accept="image/*" onChange={(e)=>e.target.files?.[0]&&upload(e.target.files[0],'logoUrl')}/></Field><Field label="Banner del restaurante"><input type="file" accept="image/*" onChange={(e)=>e.target.files?.[0]&&upload(e.target.files[0],'bannerUrl')}/></Field><Input label="Inicio atención" type="time" value={range.start} onChange={(v)=>setRange('start',v)}/><Input label="Fin atención" type="time" value={range.end} onChange={(v)=>setRange('end',v)}/><Select label="Intervalo de reservas" value={String(range.intervalMinutes)} onChange={(v)=>setRange('intervalMinutes',Number(v))}><option value="10">Cada 10 minutos</option><option value="15">Cada 15 minutos</option><option value="20">Cada 20 minutos</option><option value="30">Cada 30 minutos</option></Select><Input label="Cupo por intervalo" value={range.capacity} onChange={(v)=>setRange('capacity',Number(v))}/><button className="primary-btn" onClick={save}>Guardar perfil</button></div>{form.design.logoUrl&&<img className="preview-img" src={asset(form.design.logoUrl)} onError={safeImg}/>} {form.design.bannerUrl&&<img className="banner-preview" src={asset(form.design.bannerUrl)} onError={safeImg}/>}</section>; }
function RestaurantPreview() { const { data: me, loading } = useRestaurant(); const [date,setDate]=useState(today()); const restaurant = me?.restaurant; const {data:preview,loading:l2}=useLoad(()=>restaurant?api(`/restaurants/${restaurant.slug}/public?date=${date}`):Promise.resolve(null),[restaurant?.slug,date]); if (loading||l2) return <Loading/>; if (!restaurant) return <Empty text="No hay restaurante para previsualizar."/>; const menu=preview?.menu; const byCat=asArray(menu?.items).reduce((a,x)=>({...a,[x.category]:[...(a[x.category]||[]),x]}),{}); return <div className="page-grid"><section className="card"><h3>Previsualización como cliente</h3><p>Interactúa con el perfil publicado sin generar órdenes ni salir de este panel.</p><div className="mobile-app preview-phone"><div className="mobile-page"><div className="restaurant-banner">{restaurant.design?.bannerUrl ? <img src={asset(restaurant.design.bannerUrl)} onError={safeImg}/> : <div className="food-placeholder"><ChefHat/></div>}<div className="preview-title">{restaurant.design?.logoUrl ? <img className="preview-logo" src={asset(restaurant.design.logoUrl)} onError={safeImg}/> : <ChefHat/>}<div><h1>{restaurant.name}</h1><StarRating rating={preview?.restaurant?.rating}/><p>{restaurant.profile?.description || restaurant.address}</p><Badge>{restaurant.prestige_points || 0} puntos</Badge></div></div></div><Field label="Fecha de vista"><input type="date" value={date} onChange={(e)=>setDate(e.target.value)}/></Field>{!menu?<Empty text="Aún no hay menú publicado para esta fecha."/>:<><section className="builder card"><h3>Armar almuerzo</h3><p>Vista interactiva sin pedido. Precio base {money(menu.base_price)}.</p>{COMPONENTS.map(cat=><div key={cat} className="component-block"><h4>{categoryLabel(cat)}</h4><div className="option-list"><button>No agregar</button>{asArray(byCat[cat]).map(it=><button key={it.id}>{it.image_url?<img src={asset(it.image_url)} onError={safeImg}/>:<ChefHat size={14}/>}<span>{it.name}</span>{it.price_delta>0&&<small>+{money(it.price_delta)}</small>}</button>)}</div></div>)}</section><section className="card"><h3>Platos armados publicados</h3><div className="complete-plates">{asArray(byCat.complete_plate).map(it=><button key={it.id}>{it.image_url?<img src={asset(it.image_url)} onError={safeImg}/>:<div className="food-placeholder"><ChefHat/></div>}<strong>{it.name}</strong><span>{money(it.price||it.price_delta)}</span></button>)}</div></section></>}</div></div></section></div>; }
function RestaurantCoupons(){
  const {data:raw=[],loading,reload}=useLoad(()=>api('/restaurant/coupons'),[]);
  const {data:invRaw=[]}=useLoad(()=>api('/restaurant/inventory'),[]);
  const coupons=asArray(raw), inventory=asArray(invRaw).filter(x=>Number(x.active)!==0);
  const blank={kind:'discount',code:'',starts_at:nowLocalInput(),ends_at:'',unlimited_uses:false,max_uses:100,coverage_type:'restaurant',products:[],effect_type:'discount_percent',effect_value:50,use_requirement:false,min_purchase:0,use_previous:false,previous_purchases_required:0,description:'',is_promotion:true};
  const [form,setForm]=useState(blank); const [edit,setEdit]=useState(null); const [msg,setMsg]=useState(''); const [usage,setUsage]=useState(null);
  const payload=(src)=>({...src,products:src.coverage_type==='products'?src.products:[],min_purchase:src.use_requirement?Number(src.min_purchase||0):0,previous_purchases_required:src.use_previous?Number(src.previous_purchases_required||0):0});
  const save=async(e)=>{ e?.preventDefault?.(); setMsg(''); try{ const target=edit||form; const path=edit?`/restaurant/coupons/${edit.id}`:'/restaurant/coupons'; const method=edit?'PATCH':'POST'; await api(path,{method,body:JSON.stringify(payload(target))}); setMsg(edit?'Beneficio actualizado.':'Beneficio creado.'); setEdit(null); setForm(blank); reload();}catch(err){setMsg(err.message)} };
  const remove=async(c)=>{ if(!confirm(`¿Eliminar ${c.code}?`))return; try{const r=await api(`/restaurant/coupons/${c.id}`,{method:'DELETE'}); setMsg(r.message); reload();}catch(e){setMsg(e.message)} };
  const showUsage=async(c)=>{ try{setUsage(await api(`/coupons/${c.id}/usages`));}catch(e){setMsg(e.message)} };
  const current=edit||form; const setCurrent=(next)=> edit?setEdit(next):setForm(next);
  const productPicker=<div className="product-picker">{inventory.map(it=><label key={it.id} className="check-row"><input type="checkbox" checked={asArray(current.products).map(Number).includes(Number(it.id))} onChange={(e)=>{ const set=new Set(asArray(current.products).map(Number)); e.target.checked?set.add(Number(it.id)):set.delete(Number(it.id)); setCurrent({...current,products:[...set]}); }}/>{it.name} <small>{categoryLabel(it.category)}</small></label>)}</div>;
  const formBlock=<form className="form-grid admin-form" onSubmit={save}><Select label="Tipo de beneficio" value={current.kind} onChange={(v)=>setCurrent({...current,kind:v,code:v==='discount'?current.code||'':current.code})}><option value="coupon">Cupón redimible con código</option><option value="discount">Descuento automático sin código</option></Select>{current.kind==='coupon'&&<Input label="ID / nombre del cupón" value={current.code} onChange={(v)=>setCurrent({...current,code:v.toUpperCase()})} placeholder="Ej: DIADELASOPA"/>}<Input type="datetime-local" label="Inicio de vigencia" value={current.starts_at} onChange={(v)=>setCurrent({...current,starts_at:v})}/><Input type="datetime-local" label="Fin de vigencia" value={current.ends_at} onChange={(v)=>setCurrent({...current,ends_at:v})}/><Select label="Usos ilimitados" value={current.unlimited_uses?'yes':'no'} onChange={(v)=>setCurrent({...current,unlimited_uses:v==='yes'})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>{!current.unlimited_uses&&<Input label="Cantidad de usos" value={current.max_uses} onChange={(v)=>setCurrent({...current,max_uses:Number(v)})}/>}<Select label="Aplicación" value={current.coverage_type} onChange={(v)=>setCurrent({...current,coverage_type:v,products:[]})}><option value="restaurant">Todo el restaurante</option><option value="products">Producto(s) específico(s)</option></Select>{current.coverage_type==='products'&&productPicker}<Select label="Efecto" value={current.effect_type} onChange={(v)=>setCurrent({...current,effect_type:v})}><option value="discount_percent">Descuento %</option><option value="service_free">Servicio gratis</option><option value="service_percent">Descuento en tarifa de servicio %</option><option value="credit_fixed">Saldo para usar en el restaurante</option><option value="discount_fixed">Saldo descontable en factura</option></Select>{current.effect_type!=='service_free'&&<Input label="Valor del efecto" value={current.effect_value} onChange={(v)=>setCurrent({...current,effect_value:Number(v)})}/>}<Select label="¿Poner requisito de compra mínima?" value={current.use_requirement?'yes':'no'} onChange={(v)=>setCurrent({...current,use_requirement:v==='yes'})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>{current.use_requirement&&<Input label="Compras mayores a" value={current.min_purchase} onChange={(v)=>setCurrent({...current,min_purchase:Number(v)})}/>}<Select label="¿Premiar compras anteriores?" value={current.use_previous?'yes':'no'} onChange={(v)=>setCurrent({...current,use_previous:v==='yes'})}>{YES_NO_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select>{current.use_previous&&<Input label="Cantidad de compras anteriores" value={current.previous_purchases_required} onChange={(v)=>setCurrent({...current,previous_purchases_required:Number(v)})}/>}<Input label="Descripción interna" value={current.description} onChange={(v)=>setCurrent({...current,description:v})}/><div className="notice">El nombre visible lo calcula QuickLunch según el efecto: por ejemplo Saldo GRATIS, Servicio gratis o Descuento máximo.</div><button className="primary-btn">{edit?'Guardar cambios':'Crear beneficio del restaurante'}</button>{edit&&<button type="button" className="ghost-btn" onClick={()=>setEdit(null)}>Cancelar edición</button>}</form>;
  if(loading)return <Loading/>;
  return <div className="page-grid"><section className="card"><h3>{edit?'Modificar cupón o descuento':'Cupones y promociones del restaurante'}</h3><p>Los cupones se redimen con código desde el usuario. Los descuentos se aplican automáticamente cuando cumple requisitos.</p>{formBlock}{msg&&<p className={msg.includes('creado')||msg.includes('actualizado')||msg.includes('eliminado')?'success-msg':'error-msg'}>{msg}</p>}</section><section className="card"><h3>Beneficios publicados</h3>{!coupons.length&&<Empty text="Aún no hay promociones."/>}{coupons.map(c=><article className="coupon" key={c.id}><b>{c.code}</b><p>{c.promotionBadge || c.name} · Creado por {c.created_by}</p><span>{c.is_redeemable?'Cupón':'Descuento automático'} · {c.active?'Activo':'Inactivo'}</span><div className="actions"><button onClick={()=>setEdit({...c,kind:c.is_redeemable?'coupon':'discount',starts_at:(c.starts_at||'').replace(' ','T'),ends_at:(c.ends_at||'').replace(' ','T'),unlimited_uses:!!c.unlimited_uses,coverage_type:asArray(c.products).length?'products':'restaurant',products:asArray(c.products),effect_type:c.effect_type,effect_value:c.effect_value,use_requirement:Number(c.min_purchase)>0,min_purchase:c.min_purchase,use_previous:Number(c.previous_purchases_required)>0,previous_purchases_required:c.previous_purchases_required})}><Edit3 size={15}/> Modificar</button><button onClick={()=>showUsage(c)}><UsersRound size={15}/> Usos</button><button className="danger-btn" onClick={()=>remove(c)}><Trash2 size={15}/> Eliminar</button></div></article>)}</section>{usage&&<Modal title="Usuarios que usaron el beneficio" onClose={()=>setUsage(null)}><p>Total de usos: <b>{usage.total}</b></p><Table headers={["Usuario","Hora","Tipo","Monto"]} rows={asArray(usage.usages).map(u=>[u.user?.username||'Usuario',u.created_at,u.usage_type,money(u.amount)])}/></Modal>}</div>;
}
function RestaurantStaff() { const { data:raw=[], loading, reload }=useLoad(()=>api('/restaurant/staff'),[]); const data=asArray(raw); const blank={username:'',password:'quick2026',full_name:'',email:'',phone:'',role:'restaurant_staff',role_label:'Cajero / Operador de reservas',status:'active'}; const [form,setForm]=useState(blank); const [edit,setEdit]=useState(null); const [msg,setMsg]=useState(''); const create=async(e)=>{e.preventDefault(); setMsg(''); try{const r=await api('/restaurant/staff',{method:'POST',body:JSON.stringify(form)}); setMsg(r.message||'Colaborador creado.'); setForm(blank); reload();}catch(e){setMsg(e.message)}}; const save=async()=>{setMsg(''); try{const r=await api(`/restaurant/staff/${edit.id}`,{method:'PATCH',body:JSON.stringify(edit)}); setMsg(r.message||'Colaborador actualizado.'); setEdit(null); reload();}catch(e){setMsg(e.message)}}; const remove=async(u)=>{ if(!confirm(`¿Eliminar acceso de ${u.username}?`))return; try{const r=await api(`/restaurant/staff/${u.id}`,{method:'DELETE'}); setMsg(r.message); reload();}catch(e){setMsg(e.message)} }; if(loading)return <Loading/>; return <section className="card"><h3>Equipo del restaurante</h3><form className="form-grid" onSubmit={create}><Input label="Usuario" value={form.username} onChange={(v)=>setForm({...form,username:v})}/><Input label="Contraseña" value={form.password} onChange={(v)=>setForm({...form,password:v})}/><Input label="Nombre" value={form.full_name} onChange={(v)=>setForm({...form,full_name:v})}/><Input label="Correo" value={form.email} onChange={(v)=>setForm({...form,email:v})}/><Input label="Celular" value={form.phone} onChange={(v)=>setForm({...form,phone:v})}/><Select label="Rol" value={form.role} onChange={(v)=>setForm({...form,role:v})}><option value="restaurant_staff">Operador/cajero</option><option value="restaurant_owner">Dueño asociado</option></Select><Input label="Nombre interno del rol" value={form.role_label} onChange={(v)=>setForm({...form,role_label:v})}/><button className="primary-btn">Crear colaborador</button></form>{msg&&<p className={msg.includes('creado')||msg.includes('actualizado')||msg.includes('eliminado')?'success-msg':'error-msg'}>{msg}</p>}<Table headers={["Usuario","Nombre","Rol","Estado","Acciones"]} rows={data.map(u=>[u.username,u.full_name,u.role_label,u.status,<div className="actions"><button onClick={()=>setEdit({...u,password:''})}><Edit3 size={15}/> Editar</button><button className="danger-btn" onClick={()=>remove(u)}><Trash2 size={15}/> Quitar</button></div>])}/>{edit&&<Modal title="Modificar colaborador" onClose={()=>setEdit(null)}><div className="form-grid"><Input label="Usuario" value={edit.username} onChange={(v)=>setEdit({...edit,username:v})}/><Input label="Nombre" value={edit.full_name} onChange={(v)=>setEdit({...edit,full_name:v})}/><Input label="Correo" value={edit.email} onChange={(v)=>setEdit({...edit,email:v})}/><Input label="Celular" value={edit.phone} onChange={(v)=>setEdit({...edit,phone:v})}/><Input label="Nueva contraseña opcional" value={edit.password} onChange={(v)=>setEdit({...edit,password:v})}/><Select label="Rol" value={edit.role} onChange={(v)=>setEdit({...edit,role:v})}><option value="restaurant_staff">Operador/cajero</option><option value="restaurant_owner">Dueño asociado</option></Select><Input label="Nombre interno del rol" value={edit.role_label} onChange={(v)=>setEdit({...edit,role_label:v})}/><Select label="Estado" value={edit.status} onChange={(v)=>setEdit({...edit,status:v})}>{STATUS_OPTIONS.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</Select><button className="primary-btn" onClick={save}>{tx('Guardar cambios',lang)}</button></div></Modal>}</section>; }
function MobileShell({children}){ const {logout,account}=useAuth(); useAppChromePrefs(account); const lang=appPrefs(account).language||'es'; const nav=[['/home',Home,'Inicio'],['/home/pedidos',ShoppingBag,'Pedidos'],['/home/membresia',Crown,'Membresía'],['/home/soporte',MessageCircle,'Soporte'],['/home/cuenta',UserRound,'Cuenta']]; return <div className={`mobile-app ${membershipClass(account)}`}><header className="mobile-head"><BackButton label="" fallback="/home" className="back-btn mini"/><Logo/><button onClick={logout}><LogOut size={18}/></button></header><SystemStatusBar compact/><UsabilityHelp/><main>{children}</main><nav className="bottom-nav">{nav.map(([to,Icon,label])=><Link key={to} to={to}><Icon size={18}/><span>{tx(label, lang)}</span></Link>)}</nav></div>; }

function AiMini(){ const {account}=useAuth(); const lang=appPrefs(account).language||'es'; const {data}=useLoad(()=>api('/ai/insights'),[]); const insights=asArray(data?.insights); if(!insights.length)return null; return <section className="card ai-v2"><h3><Sparkles size={18}/> {tx('IA QuickLunch V2',lang)}</h3>{insights.slice(0,3).map((t,i)=><p key={i}>{tx(t,lang)}</p>)}</section>; }
function RestaurantAiAdvisor({restaurantId}){ const {account}=useAuth(); const lang=appPrefs(account).language||'es'; const {data}=useLoad(()=>restaurantId?api(`/ai/insights?restaurant_id=${restaurantId}`):Promise.resolve(null),[restaurantId]); const insights=asArray(data?.insights); if(!insights.length)return null; return <section className="card ai-v2"><h3><Sparkles size={18}/> {tx('Sugerencia inteligente para este restaurante',lang)}</h3>{insights.slice(0,3).map((t,i)=><p key={i}>{tx(t,lang)}</p>)}</section>; }
function CustomerApp() {
  const { account, booting } = useAuth();
  if (booting) return <Loading/>;
  if (!account || !(account.role === 'owner' || isCustomerAccessRole(account.role))) {
    return <LoginCard target="customer" title="QuickLunch" subtitle="Pide tu corrientazo, reserva tu hora de recogida y reclama con código." allowRegister />;
  }
  return <MobileShell><Routes>
    <Route index element={<CustomerHome/>}/>
    <Route path="restaurante/:slug" element={<CustomerRestaurant/>}/>
    <Route path="pedidos" element={<CustomerOrders/>}/>
    <Route path="cupones" element={<CustomerCoupons/>}/>
    <Route path="membresia" element={<MembershipPage/>}/>
    <Route path="soporte" element={<SupportPanel/>}/>
    <Route path="cuenta" element={<CustomerAccount/>}/>
    <Route path="*" element={<Navigate to="/home" replace/>}/>
  </Routes></MobileShell>;
}
function CustomerHome(){ const {data:raw=[],loading,error}=useLoad(()=>api('/restaurants/public'),[]); const data=asArray(raw); if(loading)return <Loading/>; if(error)return <div className="mobile-page"><Empty text={error}/></div>; return <div className="mobile-page"><section className="mobile-hero"><h1>Elige tu corrientazo</h1><p>Cupos por hora, código de entrega y recomendaciones según tus gustos.</p></section><MapPanel count={data.length}/>{!data.length && <Empty text="Todavía no hay restaurantes activos. Activa o crea uno desde el panel administrativo."/>}<div className="restaurant-grid">{data.map(r=> r.menuPublished ? <Link className={`restaurant-card ${r.promotion?'promoted':''}`} to={`/home/restaurante/${r.slug}`} key={r.id}>{r.design?.bannerUrl?<img src={asset(r.design.bannerUrl)} onError={safeImg}/>:<div className="food-placeholder"><ChefHat/></div>}<div><h3>{r.name}</h3><p>{r.address}</p><Badge>{r.prestige_points||0} puntos</Badge><StarRating rating={r.rating}/>{r.promotion&&<span className="promo-ribbon">{r.promotion.promotionBadge}</span>}</div></Link> : <div className="restaurant-card disabled" key={r.id}>{r.design?.bannerUrl?<img src={asset(r.design.bannerUrl)} onError={safeImg}/>:<div className="food-placeholder"><ChefHat/></div>}<div className="soon-badge">Disponible en breve</div><div><h3>{r.name}</h3><p>{r.address}</p><Badge>{r.prestige_points||0} puntos</Badge><StarRating rating={r.rating}/></div></div>)}</div><AiMini/></div>; }
function CustomerRestaurant(){ const {slug}=useParams(); const [date,setDate]=useState(today()); const {data,loading,error,reload}=useLoad(()=>api(`/restaurants/${slug}/public?date=${date}`),[slug,date]); const [settings,setSettings]=useState(null); useEffect(()=>{api('/settings').then(setSettings).catch(()=>{});},[]); if(loading)return <Loading/>; if(error)return <div className="mobile-page"><Empty text={error}/><Link className="primary-btn" to="/home">Volver a restaurantes</Link></div>; if(!data?.restaurant)return <Empty text="Restaurante no encontrado o todavía no está activo."/>; return <OrderBuilder data={data} date={date} setDate={setDate} reload={reload} settings={settings}/>; }
function OrderBuilder({data,date,setDate,settings}){ const nav=useNavigate(); const {account}=useAuth(); const {restaurant,menu}=data; const [cart,setCart]=useState([]); const [current,setCurrent]=useState({ type:'full', components:{}, extras:[] }); const [pickup,setPickup]=useState(''); const [payment,setPayment]=useState('online'); const [coupon,setCoupon]=useState(''); const [useCredits,setUseCredits]=useState(false); const [msg,setMsg]=useState(''); const {data:rawSlots=[]}=useLoad(()=>api(`/restaurants/${restaurant.id}/slots?date=${date}`),[restaurant.id,date,cart.length]); const {data:creditsRaw=[]}=useLoad(()=>api('/customer/credits'),[]); const validCredits=asArray(creditsRaw).filter(c=>!c.restaurant_id || Number(c.restaurant_id)===Number(restaurant.id)); if(!menu)return <div className="mobile-page"><h2>{restaurant.name}</h2><Empty text="Este restaurante todavía no publicó menú para hoy."/></div>; const byCat=asArray(menu.items).reduce((a,x)=>({...a,[x.category]:[...(a[x.category]||[]),x]}),{}); const base=Number(menu.base_price||15000); const fullTotal=()=> base + Object.values(current.components).reduce((s,x)=>s+Number(x?.price_delta||0),0)+current.extras.reduce((s,x)=>s+Number(x.price_delta||0),0); const addFull=()=>{ if(cart.length>=10)return setMsg('Máximo 10 almuerzos por pedido.'); const comps=COMPONENTS.map((category)=>{ const item=current.components[category]; return item?{category,...item}: {category,name:'Sin '+categoryLabel(category),skipped:true}; }); setCart([...cart,{type:'Almuerzo completo personalizable',label:'Almuerzo completo',base_price:base,components:comps,extras:current.extras,total:fullTotal()}]); setMsg('Almuerzo agregado al pedido.');}; const addSimple=(label,total,extra={})=>{ if(cart.length>=10)return setMsg('Máximo 10 almuerzos por pedido.'); setCart([...cart,{type:label,label,total,...extra}]); setMsg('Plato agregado al pedido.');}; const submit=async()=>{ setMsg(''); try{ if(!cart.length)throw new Error('Agrega al menos un almuerzo.'); if(!pickup)throw new Error('Selecciona hora de recogida.'); await api('/orders',{method:'POST',body:JSON.stringify({restaurant_id:restaurant.id,menu_id:menu.id,pickup_date:date,pickup_time:pickup,payment_method:payment,lunches:cart,coupon_code:coupon,use_credits:useCredits})}); nav('/home/pedidos'); }catch(e){setMsg(e.message)} }; const rawFee=(settings?.fees?.[payment] || (payment==='online'?1500:1000))*Math.max(1,cart.length); const discountRate=membershipFeeDiscount(account, restaurant.id); const fee=Math.max(0, rawFee-Math.round(rawFee*discountRate)); const subtotal=cart.reduce((s,x)=>s+x.total,0); const creditTotal=validCredits.reduce((s,c)=>s+Number(c.balance||0),0); return <div className={`mobile-page ${membershipClass(account)}`}><div className="restaurant-banner">{restaurant.design?.bannerUrl&&<img src={asset(restaurant.design.bannerUrl)} onError={safeImg}/>}<h1>{restaurant.name}</h1><StarRating rating={restaurant.rating}/><p>{restaurant.profile?.description||restaurant.address}</p></div><RestaurantAiAdvisor restaurantId={restaurant.id}/>{isMembershipActive(account)&&<section className="membership-mini"><Crown size={18}/><b>{membershipLabel(account)}</b><span>{account?.membership_type==='gold'?`Gold: puedes usar tu tiquetera/saldo en este restaurante si está disponible.`:(discountRate?`Beneficio aplicado: -${Math.round(discountRate*100)}% en tarifa de servicio.`:'Tu membresía está activa; revisa si aplica a este restaurante.')}</span></section>}<Field label="Fecha"><input type="date" value={date} onChange={(e)=>setDate(e.target.value)}/></Field><section className="builder card"><h3>Arma tu almuerzo completo</h3><p>Precio base {money(base)}. Puedes dejar un componente sin agregar; el precio no cambia. Los especiales suman adicional.</p>{COMPONENTS.map(cat=><div key={cat} className="component-block"><h4>{categoryLabel(cat)}</h4><div className="option-list"><button className={!current.components[cat]?'selected':''} onClick={()=>setCurrent({...current,components:{...current.components,[cat]:null}})}>No agregar</button>{asArray(byCat[cat]).map(it=><button key={it.id} className={current.components[cat]?.id===it.id?'selected':''} onClick={()=>setCurrent({...current,components:{...current.components,[cat]:it}})}>{it.image_url?<img src={asset(it.image_url)} onError={safeImg}/>:<ChefHat size={14}/>}<span>{it.name}</span>{it.price_delta>0&&<small>+{money(it.price_delta)}</small>}</button>)}</div></div>)}<h4>Adicionales fuera del plato</h4><div className="option-list">{asArray(byCat.extra).map(it=><button key={it.id} className={current.extras.find(x=>x.id===it.id)?'selected':''} onClick={()=>setCurrent({...current,extras: current.extras.find(x=>x.id===it.id)?current.extras.filter(x=>x.id!==it.id):[...current.extras,it]})}>{it.image_url?<img src={asset(it.image_url)} onError={safeImg}/>:<ChefHat size={14}/>} {it.name} +{money(it.price_delta)}</button>)}</div><button className="primary-btn" onClick={addFull}>Agregar almuerzo: {money(fullTotal())}</button></section><section className="card"><h3>Opciones separadas</h3><div className="plate-grid">{menu.sell_soup_separately? <button onClick={()=>addSimple('Sopa sola con jugo',Number(menu.soup_price||6000))}>Sopa con jugo<br/><b>{money(menu.soup_price)}</b></button>:null}{menu.sell_tray_separately? <button onClick={()=>addSimple('Bandeja sola con jugo',Number(menu.tray_price||13000))}>Bandeja con jugo<br/><b>{money(menu.tray_price)}</b></button>:null}</div></section><section className="card"><h3>Platos armados</h3><div className="complete-plates">{asArray(byCat.complete_plate).map(it=><button key={it.id} onClick={()=>addSimple(it.name,Number(it.price||it.price_delta||0),{complete_plate:it})}>{it.image_url?<img src={asset(it.image_url)} onError={safeImg}/>:<div className="food-placeholder"><ChefHat/></div>}<strong>{it.name}</strong><span>{money(it.price||it.price_delta)}</span></button>)}</div></section><section className="card checkout-card"><h3>Pedido ({cart.length}/10)</h3>{cart.map((l,i)=><p key={i}>{i+1}. {l.label} — {money(l.total)} <button onClick={()=>setCart(cart.filter((_,j)=>j!==i))}>Quitar</button></p>)}<Field label="Hora de recogida"><select value={pickup} onChange={(e)=>setPickup(e.target.value)}><option value="">Selecciona cupo disponible</option>{asArray(rawSlots).map(s=><option key={s.time} value={s.time}>{s.time} · cupos {s.available}</option>)}</select></Field><Field label="Pago"><select value={payment} onChange={(e)=>setPayment(e.target.value)}><option value="online">Pago digital: menos espera y confirmación rápida</option><option value="cash">Pago en caja</option></select></Field><Input label="Cupón" value={coupon} onChange={(v)=>setCoupon(v.toUpperCase())} placeholder="Código opcional"/>{validCredits.length>0&&<label className="check-row credit-toggle"><input type="checkbox" checked={useCredits} onChange={(e)=>setUseCredits(e.target.checked)}/> Usar créditos disponibles en este pedido ({money(creditTotal)})</label>}<div className="invoice-box"><p><span>Subtotal</span><b>{money(subtotal)}</b></p><p><span>Tarifa de servicio ({payment==='online'?'pago digital':'pago en caja'})</span><b>{money(fee)}</b></p>{discountRate>0&&<p><span>Beneficio {membershipLabel(account)}</span><b>-{money(rawFee-fee)}</b></p>}<p><span>Descuentos automáticos / cupón</span><b>{coupon ? 'Se validan al confirmar' : money(0)}</b></p><p><span>Usar saldo o créditos</span><b>{useCredits ? `-${money(Math.min(creditTotal, subtotal+fee))}` : 'No aplicado'}</b></p><p className="invoice-total"><span>Total estimado</span><b>{money(Math.max(0, subtotal+fee-(useCredits?Math.min(creditTotal, subtotal+fee):0)))}</b></p></div>{msg&&<p className={msg.includes('agregado')?'success-msg':'error-msg'}>{msg}</p>}<button className="primary-btn" disabled={!cart.length} onClick={submit}>{payment==='online'?'Pagar y generar código':'Reservar y generar código'}</button></section></div>; }
function CustomerOrders(){
  const { account } = useAuth() || {}; const lang = appPrefs(account).language || 'es';
  const {data:raw=[],loading,reload}=useLoad(()=>api('/orders/mine'),[]);
  const data=asArray(raw);
  const [support,setSupport]=useState(null);
  const [ratingOrder,setRatingOrder]=useState(null);
  useEffect(()=>{ if(support)return; const t=setInterval(()=>reload(true),2500); return()=>clearInterval(t); },[support]);
  useEffect(()=>{ const pending=data.find(o=>o.status==='claimed' && !localStorage.getItem(`ql_rated_${o.id}`)); if(pending) setRatingOrder(pending); },[data.length]);
  const cancel=async(id)=>{ try{ const r=await api(`/orders/${id}/cancel`,{method:'POST'}); alert(r.message); reload(); }catch(e){alert(e.message);} };
  if(loading)return <Loading/>;
  return <div className="mobile-page"><h2>{tx('Mis pedidos',lang)}</h2>{!data.length&&<Empty text="Aún no tienes pedidos."/>}{data.map(o=><article className={`order-card ${['claimed','cancelled','no_show'].includes(o.status)?'claimed-order':''}`} key={o.id}><div><b>{o.restaurant_name}</b> <Badge>{tx(orderStatus(o.status),lang)}</Badge><p>{o.pickup_slot} · {money(o.total)} · {o.lunch_count} {tx('almuerzo(s)',lang)}</p><p className="delivery-code-view"><b>{tx('Código de entrega',lang)}:</b> {o.status==='claimed'?tx('Código usado / inválido',lang):o.public_code}</p></div><div className="actions"><button onClick={()=>window.print()} disabled={['claimed','cancelled'].includes(o.status)}><QrCode size={16}/> {tx('Imprimir código',lang)}</button><button onClick={()=>cancel(o.id)} disabled={['claimed','preparing','ready','cancelled'].includes(o.status)}>{tx('Cancelar',lang)}</button><button onClick={()=>setSupport(o)}>{tx('Soporte',lang)}</button>{o.status==='claimed'&&<Rating order={o}/>}</div></article>)}{support&&<SupportModal order={support} onClose={()=>setSupport(null)}/>} {ratingOrder&&<RatingFloat order={ratingOrder} onClose={()=>{localStorage.setItem(`ql_rated_${ratingOrder.id}`,'skip');setRatingOrder(null)}}/>}</div>;
}
function SupportModal({order,onClose}){ const { account } = useAuth() || {}; const lang = appPrefs(account).language || 'es'; const [type,setType]=useState(''); const [body,setBody]=useState(''); const [options,setOptions]=useState([]); const [attachments,setAttachments]=useState([]); const [uploadMsg,setUploadMsg]=useState(''); useEffect(()=>{api(`/support/options/${order.id}`).then(r=>{setOptions(r.options); setType(r.options[0]||'Soporte');});},[order.id]); const send=async()=>{ await api('/support/threads',{method:'POST',body:JSON.stringify({order_id:order.id,support_type:type,subject:type,body,attachments})}); onClose();}; return <Modal title={tx('Soporte del pedido',lang)} onClose={onClose}><Select label={tx('Tipo de soporte',lang)} value={type} onChange={setType}>{options.map(o=><option key={o}>{o}</option>)}</Select><textarea value={body} onChange={(e)=>setBody(e.target.value)} placeholder={tx('Describe el problema o solicitud',lang)}/><Field label={tx('Adjuntar imagen',lang)}><input type="file" accept="image/*" onChange={async(e)=>{ const file=e.target.files?.[0]; if(!file)return; const fd=new FormData(); fd.append('image',file); try{ const r=await api('/support/upload',{method:'POST',body:fd}); setAttachments([...attachments,r.url]); setUploadMsg(tx('Imagen adjuntada.',lang)); }catch(err){ setUploadMsg(err.message); } }}/></Field>{uploadMsg&&<p className="help-msg">{uploadMsg}</p>}<button className="primary-btn" onClick={send}>Enviar soporte</button></Modal>; }
function CustomerCoupons({ embedded=false } = {}){
  const { account } = useAuth() || {}; const lang = appPrefs(account).language || 'es';
  const {data:rawCoupons=null,loading,error,reload}=useLoad(()=>api('/customer/coupons'),[]);
  const {data:rawCredits=[]}=useLoad(()=>api('/customer/credits'),[]);
  const coupons=asArray(rawCoupons?.available || rawCoupons); const wallet=asArray(rawCoupons?.wallet); const credits=asArray(rawCredits);
  const [code,setCode]=useState(''); const [msg,setMsg]=useState('');
  const redeem=async()=>{ setMsg(''); try{ const r=await api('/customer/coupons/redeem',{method:'POST',body:JSON.stringify({code})}); setMsg(r.message); setCode(''); reload(); }catch(e){setMsg(e.message)} };
  if(loading)return <Loading/>;
  return <div className={embedded?'account-coupons-panel':'mobile-page'}><h2>{tx('Cupones y créditos',lang)}</h2>{error && <p className="error-msg">{tx(error,lang)}</p>}<section className="card"><h3>{tx('Redimir código',lang)}</h3><Input label={tx('Código de cupón',lang)} value={code} onChange={(v)=>setCode(v.toUpperCase())} placeholder="Ej: QL5000"/><button className="primary-btn" onClick={redeem}>{tx('Redimir',lang)}</button>{msg&&<p className={msg.includes('redimido')?'success-msg':'error-msg'}>{tx(msg,lang)}</p>}</section><section className="card"><h3>{tx('Créditos disponibles',lang)}</h3>{!credits.length && <Empty text="Aún no tienes créditos."/>}{credits.map((c,i)=><p key={c.id||i}>{c.restaurant_name}: <b>{money(c.balance)}</b> <small>{tx(c.source,lang)}</small></p>)}</section><section className="card"><h3>{tx('Cupones activos',lang)}</h3>{!coupons.length && <Empty text="No hay cupones activos por ahora."/>}{coupons.map(c=><article className="coupon" key={c.id}><b>{c.code}</b><p>{c.name || c.description} · {c.restaurant_name||'QuickLunch'}</p><span>{c.promotionBadge || (c.effect_type==='discount_percent'?`${c.effect_value}%`:money(c.effect_value||c.discount_value))}</span></article>)}</section></div>;
}
function CustomerAccount(){
  const {account,refresh,logout}=useAuth(); const nav=useNavigate();
  const [tab,setTab]=useState('perfil');
  const prefs=appPrefs(account); const lang=prefs.language||'es';
  const [form,setForm]=useState({full_name:account?.full_name||'',email:account?.email||'',password:''});
  const [appForm,setAppForm]=useState({language:prefs.language,theme:prefs.theme,app_size:prefs.app_size});
  const [deletePass,setDeletePass]=useState(''); const [msg,setMsg]=useState('');
  const {data:creditsRaw=[]}=useLoad(()=>api('/customer/credits'),[]);
  const {data:membershipData}=useLoad(()=>api('/customer/membership/plans'),[]);
  const membershipRestaurant=asArray(membershipData?.restaurants).find(r=>Number(r.id)===Number(account?.membership_restaurant_id));
  const credits=asArray(creditsRaw); const totalCredits=credits.reduce((s,c)=>s+Number(c.balance||0),0); const goldLeft=goldLunchesLeft(account, credits, asArray(membershipData?.restaurants));
  const upload=async(file)=>{ const fd=new FormData(); fd.append('image',file); const r=await api('/customer/profile-photo',{method:'POST',body:fd}); setMsg(r.message); await refresh(); };
  const save=async()=>{ setMsg(''); try{ const r=await api('/customer/account',{method:'PATCH',body:JSON.stringify(form)}); setMsg(r.message); await refresh(); setForm({...form,password:''}); }catch(e){setMsg(e.message)} };
  const saveApp=async()=>{ setMsg(''); try{ const r=await api('/account/preferences',{method:'PATCH',body:JSON.stringify(appForm)}); setMsg(r.message); await refresh(); }catch(e){setMsg(e.message)} };
  const remove=async()=>{ setMsg(''); try{ const r=await api('/customer/account',{method:'DELETE',body:JSON.stringify({password:deletePass})}); setMsg(r.message); setTimeout(()=>{logout();nav('/home')},900); }catch(e){setMsg(e.message)} };
  return <div className={`mobile-page account-page ${membershipClass(account)}`}>
    <section className="profile-card card profile-summary-card">
      <div className={`profile-avatar ${membershipClass(account)}`}>{account?.profile_photo_url?<img src={asset(account.profile_photo_url)} onError={safeImg}/>:<UserRound size={42}/>}</div>
      <div className="profile-main-info"><h2>{account?.full_name || account?.username}</h2><p>@{account?.username} · {account?.email}</p><Badge>{membershipLabel(account)}</Badge></div>
      <div className="profile-balance-chip"><WalletCards size={18}/><span>{tx('Saldo total',lang)}</span><b>{money(totalCredits + Number(account?.wallet_balance || 0))}</b></div>
    </section>
    <div className="account-tabs"><button className={tab==='perfil'?'selected':''} onClick={()=>setTab('perfil')}>{tx('Perfil',lang)}</button><button className={tab==='cupones'?'selected':''} onClick={()=>setTab('cupones')}>{tx('Cupones',lang)}</button><button className={tab==='ajustes'?'selected':''} onClick={()=>setTab('ajustes')}>{tx('Ajustes',lang)}</button><button className={tab==='app'?'selected':''} onClick={()=>setTab('app')}>{tx('Configuración de la app',lang)}</button><button className={tab==='membresia'?'selected':''} onClick={()=>setTab('membresia')}>{tx('Membresía',lang)}</button><button className={tab==='saldos'?'selected':''} onClick={()=>setTab('saldos')}>{tx('Saldos',lang)}</button></div>
    {tab==='perfil'&&<section className="card"><h3>{tx('Resumen de cuenta',lang)}</h3><p><b>{tx('Usuario',lang)}:</b> {account?.username}</p><p><b>{tx('Membresía',lang)}:</b> {membershipLabel(account)}</p><p><b>{tx('Puntos para redención',lang)}:</b> {account?.redemption_points || 0}</p><p><b>{tx('Saldo general',lang)}:</b> {money(account?.wallet_balance)}</p><p><b>{tx('Saldo en cupones, recargas y tiqueteras',lang)}:</b> {money(totalCredits)}</p>{account?.membership_type==='gold'&&goldLeft&&<p><b>{tx('Almuerzos Gold restantes',lang)}:</b> {goldLeft.lunches} ({money(goldLeft.credit)}) en {goldLeft.restaurant?.name || membershipRestaurant?.name || 'restaurante elegido'}</p>}</section>}
    {tab==='cupones'&&<CustomerCoupons embedded/>}
    {tab==='ajustes'&&<section className="card"><h3>{tx('Ajustes de cuenta',lang)}</h3><div className="form-grid"><Input label="Nombre" value={form.full_name} onChange={(v)=>setForm({...form,full_name:v})}/><Input label="Correo de recuperación" value={form.email} onChange={(v)=>setForm({...form,email:v})}/><Input label="Nueva contraseña" type="password" placeholder="Opcional" value={form.password} onChange={(v)=>setForm({...form,password:v})}/><Field label="Cambiar foto de perfil"><input type="file" accept="image/*" onChange={(e)=>e.target.files?.[0]&&upload(e.target.files[0])}/></Field><button className="primary-btn" onClick={save}>{tx('Guardar cambios',lang)}</button></div><hr/><h4>{tx('Eliminar cuenta',lang)}</h4><p>{tx('Para eliminarla debes escribir tu contraseña actual.',lang)}</p><Input label="Contraseña actual" type="password" value={deletePass} onChange={setDeletePass}/><button className="danger-btn" disabled={!deletePass} onClick={remove}>{tx('Eliminar cuenta',lang)}</button></section>}
    {tab==='app'&&<section className="card"><h3>{tx('Configuración de la app',lang)}</h3><p className="muted">{tx('Estos ajustes cambian la experiencia visual de QuickLunch en este usuario.',lang)}</p><div className="form-grid"><Select label="Idioma" value={appForm.language} onChange={(v)=>setAppForm({...appForm,language:v})}><option value="es">Español</option><option value="en">English</option><option value="pt">Português</option></Select><Select label="Aspecto" value={appForm.theme} onChange={(v)=>setAppForm({...appForm,theme:v})}><option value="light">Claro</option><option value="dark">Oscuro</option></Select><Select label="Tamaño de app" value={appForm.app_size} onChange={(v)=>setAppForm({...appForm,app_size:v})}><option value="compact">Compacto</option><option value="normal">Normal</option><option value="large">Grande</option></Select><button className="primary-btn" onClick={saveApp}>{tx('Aplicar configuración',lang)}</button></div></section>}
    {tab==='membresia'&&<section className={`card membership-status ${membershipClass(account)}`}>{isMembershipActive(account)?<><h3>{tx('Estado de membresía',lang)}: {tx(account.membership_status,lang)}</h3><p><b>{tx('Tipo',lang)}:</b> {membershipLabel(account)}</p>{account.membership_type==='gold'?<><p><b>{tx('Beneficios disponibles hasta',lang)}:</b> {account.membership_ends_at?new Date(account.membership_ends_at).toLocaleString('es-CO'):'Sin fecha registrada'}</p><p><b>{tx('Créditos Gold restantes',lang)}:</b> {goldLeft ? `${goldLeft.lunches} almuerzos · ${money(goldLeft.credit)}` : 'se conservan hasta agotarse en el restaurante elegido.'}</p></>:<p><b>{tx('Fecha de finalización',lang)}:</b> {new Date(account.membership_ends_at).toLocaleString('es-CO')}</p>}{account.membership_status==='active'&&account.membership_type==='platinum'&&<p><b>{tx('Próximo cobro',lang)}:</b> {new Date(account.membership_next_billing_at).toLocaleString('es-CO')}</p>}{account.membership_type==='gold'&&<p><b>{tx('Restaurante elegido',lang)}:</b> {membershipRestaurant?.name || `Restaurante #${account.membership_restaurant_id}`}</p>}<div className="actions"><Link className="primary-btn" to="/home/membresia">{tx('Administrar membresía',lang)}</Link>{account.membership_status==='cancelled'&&<Link className="secondary-btn" to="/home/membresia">{tx('Reactivar membresía',lang)}</Link>}</div></>:<><h3>{tx('No tienes membresía activa',lang)}</h3><p>{tx('Activa Gold como tiquetera de tu restaurante favorito o Platinum para beneficios globales.',lang)}</p><Link className="primary-btn" to="/home/membresia">{tx('Comprar membresía',lang)}</Link></>}</section>}
    {tab==='saldos'&&<section className="card"><h3>{tx('Saldos, cupones y tiqueteras',lang)}</h3>{!credits.length&&<Empty text="Aún no tienes saldos por cupones, recargas o cancelaciones."/>}{credits.map((c,i)=><article className="credit-row" key={c.id||i}><div><b>{c.restaurant_name}</b><p>{tx(c.source || 'saldo',lang)} · {tx('úsalo cuando compres en restaurantes válidos.',lang)}</p></div><strong>{money(c.balance)}{account?.membership_type==='gold'&&Number(c.restaurant_id)===Number(account?.membership_restaurant_id)&&goldLeft?<small> · {goldLeft.lunches} almuerzos</small>:null}</strong></article>)}</section>}
    {msg&&<p className={msg.includes('correctamente')||msg.includes('actualizada')?'success-msg':'error-msg'}>{msg}</p>}
  </div>;
}
function MembershipPage(){
  const {account,refresh}=useAuth();
  const lang=appPrefs(account).language||'es';
  const [selected,setSelected]=useState({type:'gold',duration_days:15,restaurant_id:''});
  const [msg,setMsg]=useState('');
  const {data,loading,reload}=useLoad(()=>api('/customer/membership/plans'),[]);
  const {data:creditsRaw=[]}=useLoad(()=>api('/customer/credits'),[]);
  if(loading)return <Loading/>;
  const plans=data?.plans||{}; const restaurants=asArray(data?.restaurants);
  const selectedRestaurant=restaurants.find(r=>Number(r.id)===Number(selected.restaurant_id));
  const goldQuote=selectedRestaurant?.gold_quotes?.[selected.duration_days] || selectedRestaurant?.goldQuotes?.[selected.duration_days] || {};
  const goldTickets=Number(goldQuote.tickets || selected.duration_days);
  const goldBase=Number(goldQuote.basePrice || selectedRestaurant?.base_lunch_price || 15000);
  const feePerLunch=Number(goldQuote.feePerLunch || data?.defaultFees?.cash || 1000);
  const goldCredit=Number(goldQuote.creditValue || goldBase*goldTickets);
  const normalValue=Number(goldQuote.normalValue || (goldBase+feePerLunch)*goldTickets);
  const goldPrice=Number(goldQuote.price || Math.round(normalValue*0.70));
  const qlDiscount=Math.max(0,Number(goldQuote.savings || normalValue-goldPrice));
  const goldDiscountPercent=Math.round(Number(goldQuote.discountRate || 0.30)*100);
  const platinumPrice=Number(plans?.platinum?.prices?.[selected.duration_days] || plans?.platinum?.price || 16900);
  const price=selected.type==='gold'?goldPrice:platinumPrice;
  const buy=async()=>{ setMsg(''); try{ const r=await api('/customer/membership/purchase',{method:'POST',body:JSON.stringify(selected)}); setMsg(r.message); await refresh(); reload(); }catch(e){setMsg(e.message)} };
  const cancel=async()=>{ setMsg(''); try{ const r=await api('/customer/membership/cancel',{method:'PATCH'}); setMsg(r.message); await refresh(); reload(); }catch(e){setMsg(e.message)} };
  const reactivate=async()=>{ setMsg(''); try{ const r=await api('/customer/membership/reactivate',{method:'PATCH'}); setMsg(r.message); await refresh(); reload(); }catch(e){setMsg(e.message)} };
  const active=isMembershipActive(account);
  const currentRestaurant=restaurants.find(r=>Number(r.id)===Number(account?.membership_restaurant_id));
  const goldLeft=goldLunchesLeft(account, asArray(creditsRaw), restaurants);
  return <div className={`mobile-page membership-store ${selected.type==='platinum'?'membership-platinum':'membership-gold'}`}>
    <section className="membership-hero premium-hero"><div className="premium-logo-lockup"><Logo/><div><span className="eyebrow">{tx('Club QuickLunch',lang)}</span><h1>{tx('Membresías Gold y Platinum',lang)}</h1></div></div><p>{tx('Gold es una tiquetera sin vencimiento para un restaurante. Platinum cuesta',lang)} {money(platinumPrice)} {tx('y activa beneficios globales.',lang)}</p><div className="premium-badges"><Badge>{tx('Gold: 15 o 30 almuerzos',lang)}</Badge><Badge>{tx('Platinum fijo',lang)}</Badge><Badge>{tx('Pago simulado',lang)}</Badge></div></section>
    {active&&<section className={`card membership-current ${membershipClass(account)}`}><h3>{tx('Tu membresía actual',lang)}</h3><p><b>{tx('Tipo',lang)}:</b> {membershipLabel(account)}</p><p><b>{tx('Estado',lang)}:</b> {tx(account.membership_status,lang)}</p>{account.membership_type==='gold'?<><p><b>{tx('Beneficios disponibles hasta',lang)}:</b> {account.membership_ends_at?new Date(account.membership_ends_at).toLocaleString(lang==='es'?'es-CO':lang):tx('Sin fecha registrada',lang)}</p><p><b>{tx('Créditos Gold restantes',lang)}:</b> {goldLeft ? `${goldLeft.lunches} ${tx('almuerzos',lang)} · ${money(goldLeft.credit)}` : tx('Se conservan hasta agotarse.',lang)}</p></>:<p><b>{tx('Fecha de finalización',lang)}:</b> {new Date(account.membership_ends_at).toLocaleString(lang==='es'?'es-CO':lang)}</p>}{account.membership_type==='gold'&&<p><b>{tx('Restaurante elegido',lang)}:</b> {currentRestaurant?.name || `Restaurante #${account.membership_restaurant_id}`}</p>}<div className="actions">{account.membership_status==='active'?<button className="danger-btn" onClick={cancel}>{tx('Cancelar membresía',lang)}</button>:<button className="primary-btn" onClick={reactivate}>{tx('Reactivar membresía',lang)}</button>}{account.membership_type==='platinum'&&<button className="primary-btn" onClick={()=>setSelected({...selected,type:'gold',restaurant_id:selected.restaurant_id||restaurants[0]?.id||''})}>{tx('Cambiar a Gold',lang)}</button>}</div></section>}
    <div className="plan-grid luxury-plans"><button className={selected.type==='gold'?'selected gold-plan':'gold-plan'} onClick={()=>setSelected({...selected,type:'gold'})}><small>{tx('Tiquetera selecta',lang)}</small><h2>Gold</h2><p>{tx('Recarga almuerzos para un restaurante específico con precio menor al valor normal.',lang)}</p><b>{tx('Precio variable según restaurante',lang)}</b></button><button className={selected.type==='platinum'?'selected platinum-plan':'platinum-plan'} onClick={()=>setSelected({...selected,type:'platinum',restaurant_id:''})}><small>{tx('Plan global',lang)}</small><h2>Platinum</h2><p>{tx('50% de descuento en tarifa de servicio en toda QuickLunch, sin elegir restaurante.',lang)}</p><b>{money(platinumPrice)}</b></button></div>
    <section className="card membership-config-card"><h3>{active?tx('Renovar o cambiar plan',lang):tx('Configura tu plan',lang)}</h3><Select label="Plan" value={String(selected.duration_days)} onChange={(v)=>setSelected({...selected,duration_days:Number(v)})}><option value="15">{tx('15 almuerzos / 15 días Platinum',lang)}</option><option value="30">{tx('30 almuerzos / 30 días Platinum',lang)}</option></Select>{selected.type==='gold'&&<Select label="Restaurante elegido para Gold" value={selected.restaurant_id} onChange={(v)=>setSelected({...selected,restaurant_id:Number(v)})}><option value="">{tx('Selecciona restaurante',lang)}</option>{restaurants.map(r=><option key={r.id} value={r.id}>{r.name} · corrientazo base {money(r.base_lunch_price)}</option>)}</Select>}
      {selected.type==='gold'?<div className="ticketera-box invoice-box"><h4>{tx('Factura de membresía Gold',lang)}</h4><p><span>{tx('Precio almuerzo',lang)} {selectedRestaurant?.name||tx('restaurante elegido',lang)}</span><b>{money(goldBase)}</b></p><p><span>{tx('Tarifa de servicio por almuerzo',lang)}</span><b>{money(feePerLunch)}</b></p><p><span>{tx('Subtotal para',lang)} {goldTickets} {tx('almuerzos',lang)}</span><b>{money(normalValue)}</b></p><p><span>{tx('Crédito recibido para almuerzos',lang)}</span><b>{money(goldCredit)}</b></p><p><span>{tx('Descuento Gold aplicado',lang)} ({goldDiscountPercent}%)</span><b>-{money(qlDiscount)}</b></p><p className="total-line"><span>{tx('Total a pagar',lang)}</span><b>{money(price)}</b></p><small>{tx('Gold exonera la tarifa de servicio cuando usas estos créditos en el restaurante elegido.',lang)}</small></div>:<div className="ticketera-box platinum-box"><p><b>{tx('Platinum fijo',lang)}</b></p><p>{tx('Precio único',lang)}: <b>{money(platinumPrice)}</b></p><p className="muted">{tx('Aplica beneficios globales definidos para usuarios Platinum.',lang)}</p></div>}
      <ul className="check-list">{asArray(plans?.[selected.type]?.benefits).map(b=><li key={b}>{tx(b,lang)}</li>)}</ul><button className="primary-btn luxury-pay" disabled={selected.type==='gold'&&!selected.restaurant_id} onClick={buy}>{tx('Pagar membresía simulada',lang)}</button>{msg&&<p className={msg.includes('activada')||msg.includes('cancelada')||msg.includes('reactivada')?'success-msg':'error-msg'}>{tx(msg,lang)}</p>}</section>
  </div>;
}

function SupportPanel(){
  const {account}=useAuth();
  const {data:raw=[],loading,error,reload}=useLoad(()=>api('/support/threads'),[]);
  const threads=asArray(raw); const [active,setActive]=useState(null); const [body,setBody]=useState(''); const [channel,setChannel]=useState(account?.role==='customer'?'customer':account?.role?.includes('restaurant')?'restaurant':'customer'); const [msg,setMsg]=useState(''); const [rewardOpen,setRewardOpen]=useState(false); const [sanctionOpen,setSanctionOpen]=useState(false); const [amount,setAmount]=useState(5000);
  const visibleMessages=asArray(active?.messages).filter(m=>['owner','admin'].includes(account?.role)?m.channel===channel:true);
  const closed=active?.status==='resolved';
  const refreshActive=async()=>{ const updated=await api('/support/threads'); const next=asArray(updated).find(t=>t.id===active?.id); setActive(next||null); reload(); };
  const send=async()=>{ if(!active||!body.trim())return setMsg('Escribe un mensaje.'); if(closed)return setMsg('Este caso ya fue resuelto. Solo un owner/admin puede reabrirlo.'); try{ await api(`/support/threads/${active.id}/messages`,{method:'POST',body:JSON.stringify({body,channel})}); setMsg('Mensaje enviado.'); setBody(''); await refreshActive(); }catch(e){setMsg(e.message)} };
  const action=async(payload)=>{ try{ await api(`/support/threads/${active.id}/action`,{method:'PATCH',body:JSON.stringify(payload)}); setMsg('Acción realizada correctamente.'); setRewardOpen(false); setSanctionOpen(false); await refreshActive(); }catch(e){setMsg(e.message)} };
  if(loading)return <Loading/>;
  return <section className="card support-page"><h3>Centro de soporte funcional</h3>{error&&<p className="error-msg">{error}</p>}{msg&&<p className={msg.includes('correctamente')||msg.includes('enviado')?'success-msg':'error-msg'}>{msg}</p>}<div className="support-grid"><div className="thread-list">{!threads.length&&<Empty text="No hay casos de soporte por ahora."/>}{threads.map(t=><button className={`support-thread ${active?.id===t.id?'selected':''}`} key={t.id} onClick={()=>{setActive(t); setChannel(account?.role?.includes('restaurant')?'restaurant':'customer')}}><b>{t.subject}</b><span>{t.support_type} · {t.status}</span>{t.restaurant_involved? <Badge>Restaurante implicado</Badge>:<small>Solo usuario ↔ QuickLunch</small>}</button>)}</div>{active&&<div className="support-chat social-chat"><div className="chat-head"><div><h4>{active.subject}</h4><small>Caso #{active.id} · {active.status}</small></div>{['owner','admin'].includes(account.role)&&<div className="chat-tabs"><button className={channel==='customer'?'selected':''} onClick={()=>setChannel('customer')}>Usuario ↔ QuickLunch</button>{active.restaurant_involved&&<button className={channel==='restaurant'?'selected':''} onClick={()=>setChannel('restaurant')}>Restaurante ↔ QuickLunch</button>}<button className={channel==='admin'?'selected':''} onClick={()=>setChannel('admin')}>Notas internas</button></div>}</div><div className="chat-box">{asArray(active.attachments).length>0&&<div className="support-attachments"><b>Imágenes adjuntas por el usuario</b><div>{asArray(active.attachments).map((u,i)=><a href={asset(u)} target="_blank" key={i}><img src={asset(u)} onError={safeImg}/></a>)}</div></div>}{!visibleMessages.length&&<Empty text="Aún no hay mensajes en este chat."/>}{visibleMessages.map(m=><div key={m.id} className={`bubble ${m.sender_role===account.role?'me':'other'} ${m.channel}`}><b>{m.sender_name}</b><p>{m.body}</p><small>{m.created_at}</small></div>)}</div><div className="composer"><textarea disabled={closed} value={body} onChange={(e)=>setBody(e.target.value)} placeholder={closed?'Caso resuelto: solo lectura':'Escribe un mensaje para este chat'}/><button className="primary-btn" disabled={closed} onClick={send}>Enviar</button></div>{['owner','admin'].includes(account.role)&&<div className="support-actions">{closed&&<button onClick={()=>action({reopen:true})}>Reabrir caso</button>}{!active.restaurant_involved&&<button onClick={()=>action({involve_restaurant:true})}>Implicar restaurante</button>}<button disabled={closed} onClick={()=>setRewardOpen(true)}>Recompensar usuario</button><button disabled={closed} onClick={()=>setSanctionOpen(true)}>Sancionar restaurante</button><button disabled={closed} onClick={()=>action({deny_request:true,resolve:true})}>Negar y resolver</button><button disabled={closed} className="primary-btn" onClick={()=>action({resolve:true})}>Marcar resuelto</button></div>}</div>}</div>{rewardOpen&&<Modal title="Monto de recompensa" onClose={()=>setRewardOpen(false)}><Input label="Valor a dar al usuario" value={amount} onChange={(v)=>setAmount(Number(v))}/><button className="primary-btn" onClick={()=>action({reward_user:true,reward_amount:amount})}>Confirmar recompensa</button></Modal>}{sanctionOpen&&<Modal title="Monto de sanción al restaurante" onClose={()=>setSanctionOpen(false)}><Input label="Valor a descontar de ganancias" value={amount} onChange={(v)=>setAmount(Number(v))}/><Input label="Motivo" value={'Sanción desde soporte'} onChange={()=>{}}/><button className="danger-btn" onClick={()=>action({sanction_restaurant:true,penalty_amount:amount,penalty_points:1,penalty_reason:'Sanción desde soporte'})}>Confirmar sanción</button></Modal>}</section>;
}

function RatingStarsInput({ value, onChange }) {
  return <div className="rating-stars-input" aria-label="Calificación del restaurante">{[1,2,3,4,5].map((n)=><button type="button" key={n} className={n<=Number(value||0)?'selected':''} onClick={()=>onChange(n)}>★</button>)}</div>;
}

function Rating({ order }) {
  const [open, setOpen] = useState(false);
  return <>{!localStorage.getItem(`ql_rated_${order.id}`)&&<button onClick={()=>setOpen(true)}><Star size={16}/> Calificar</button>}{open&&<RatingFloat order={order} onClose={()=>setOpen(false)}/>}</>;
}

function RatingFloat({ order, onClose }) {
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState('');
  const [msg, setMsg] = useState('');
  const submit = async () => {
    setMsg('');
    try {
      const r = await api(`/orders/${order.id}/rating`, { method:'POST', body:JSON.stringify({ rating, comment }) });
      localStorage.setItem(`ql_rated_${order.id}`, 'yes');
      setMsg(r.message || 'Calificación registrada.');
      setTimeout(onClose, 700);
    } catch (e) { setMsg(e.message); }
  };
  return <div className="rating-float"><div className="rating-modal"><button className="close-x" onClick={onClose}>×</button><h3>¿Cómo estuvo tu experiencia?</h3><p>Califica el pedido en {order.restaurant_name}. Tu opinión ayuda a otros usuarios y mejora el servicio.</p><RatingStarsInput value={rating} onChange={setRating}/><textarea value={comment} onChange={(e)=>setComment(e.target.value)} placeholder="Comentarios o sugerencias opcionales"/><button className="primary-btn" onClick={submit}>Enviar calificación</button>{msg&&<p className={msg.includes('registrada')?'success-msg':'error-msg'}>{msg}</p>}</div></div>;
}

function ConfirmPage() {
  const { code } = useParams();
  const { data, loading, error } = useLoad(() => api(`/orders/confirm/${encodeURIComponent(code || '')}`), [code]);
  if (loading) return <Loading label="Consultando código de entrega..."/>;
  if (error) return <div className="page-grid"><section className="card panic"><AlertTriangle/><h2>Código no encontrado</h2><p>{error}</p><Link className="primary-btn" to="/home">Volver a QuickLunch</Link></section></div>;
  return <div className="page-grid"><section className="card receipt-card"><Logo/><h2>Confirmación de pedido</h2><p><b>ID del pedido:</b> #{data.id}</p><p><b>Restaurante:</b> {data.restaurant_name}</p><p><b>Cliente:</b> {data.customer_name}</p><p><b>Estado:</b> {orderStatus(data.status)}</p><p><b>Hora de recogida:</b> {data.pickup_slot}</p><p><b>Total:</b> {money(data.total)}</p><p className="muted">Este código solo se valida desde el panel del restaurante al momento de entregar el pedido.</p><Link className="primary-btn" to="/home/pedidos">Ver mis pedidos</Link></section></div>;
}

function App(){ return <ErrorBoundary><AuthProvider><BrowserRouter><Routes><Route path="/admin/*" element={<AdminApp/>}/><Route path="/home/*" element={<CustomerApp/>}/><Route path="/confirmar/:code" element={<ConfirmPage/>}/><Route path="/" element={<Navigate to="/home" replace/>}/><Route path="/:slug/*" element={<RestaurantApp/>}/></Routes></BrowserRouter></AuthProvider></ErrorBoundary>; }

try {
  createRoot(document.getElementById('root')).render(<App/>);
  setTimeout(() => {
    const fallback = document.getElementById('ql-boot-fallback');
    if (fallback) fallback.style.display = 'none';
  }, 100);
} catch (error) {
  const box = document.getElementById('ql-boot-error');
  if (box) {
    box.style.display = 'block';
    box.textContent = 'Error de carga: ' + (error?.message || error);
  }
}

